const Q: ExamQuestion[] = [
  // ═══════════════════════════════════════
  // LIFE INSURANCE BASICS (25 questions)
  // ═══════════════════════════════════════
  { id: 1, category: 'Life Insurance Basics', question: 'What is the primary purpose of life insurance?', options: ['Investment growth', 'Provide financial protection against the risk of death', 'Tax shelter', 'Retirement income'], correctIndex: 1, rationale: 'Life insurance is primarily designed to provide financial protection to beneficiaries in the event of the insured\'s death.' },
  { id: 2, category: 'Life Insurance Basics', question: 'Which type of life insurance provides coverage for a specific period of time?', options: ['Whole life', 'Universal life', 'Term life', 'Variable life'], correctIndex: 2, rationale: 'Term life insurance provides coverage for a specific period (term) such as 10, 20, or 30 years. If the insured dies during the term, benefits are paid.' },
  { id: 3, category: 'Life Insurance Basics', question: 'What is the cash value component found in?', options: ['Term life insurance', 'Permanent life insurance', 'Group term insurance', 'Accidental death insurance'], correctIndex: 1, rationale: 'Permanent life insurance (whole life, universal life, variable life) includes a cash value component that grows over time. Term life does not have cash value.' },
  { id: 4, category: 'Life Insurance Basics', question: 'A person is considered a minor until what age?', options: ['16', '17', '18', '21'], correctIndex: 2, rationale: 'A person is considered a minor until the age of 18. Minors cannot enter into binding insurance contracts.' },
  { id: 5, category: 'Life Insurance Basics', question: 'Which life insurance policy has a guaranteed death benefit and fixed premiums?', options: ['Term life', 'Whole life', 'Universal life', 'Variable life'], correctIndex: 1, rationale: 'Whole life insurance provides a guaranteed death benefit, fixed premiums, and guaranteed cash value growth throughout the insured\'s lifetime.' },
  { id: 6, category: 'Life Insurance Basics', question: 'What does "face amount" refer to in a life insurance policy?', options: ['The annual premium', 'The cash surrender value', 'The death benefit amount stated in the policy', 'The dividend amount'], correctIndex: 2, rationale: 'The face amount (or face value) is the death benefit amount stated on the policy that will be paid to beneficiaries upon the insured\'s death.' },
  { id: 7, category: 'Life Insurance Basics', question: 'In an Indexed Universal Life (IUL) policy, the cash value growth is tied to:', options: ['Bond market performance', 'A stock market index like the S&P 500', 'Real estate values', 'Government treasury rates'], correctIndex: 1, rationale: 'IUL policies tie cash value growth to the performance of a stock market index (like the S&P 500) with a floor (minimum guarantee) and a cap (maximum rate).' },
  { id: 8, category: 'Life Insurance Basics', question: 'What is the "grace period" in a life insurance policy?', options: ['Time to decide if you want the policy', 'Time allowed to pay a past-due premium before the policy lapses', 'Time to file a claim', 'Waiting period before coverage begins'], correctIndex: 1, rationale: 'The grace period (typically 30-31 days) is the time after a premium due date during which the policy remains in force even if the premium hasn\'t been paid.' },
  { id: 9, category: 'Life Insurance Basics', question: 'Who is the "insured" in a life insurance policy?', options: ['The person who pays premiums', 'The person whose life is covered', 'The beneficiary', 'The insurance company'], correctIndex: 1, rationale: 'The insured is the person whose life is covered by the policy. The death benefit is paid when this person dies.' },
  { id: 10, category: 'Life Insurance Basics', question: 'What is a "beneficiary"?', options: ['The insurance agent', 'The person who owns the policy', 'The person or entity designated to receive the death benefit', 'The underwriter'], correctIndex: 2, rationale: 'A beneficiary is the person, persons, or entity named in the policy to receive the death benefit proceeds when the insured dies.' },
  { id: 11, category: 'Life Insurance Basics', question: 'What is a "rider" on an insurance policy?', options: ['The policyholder', 'An additional provision that adds or modifies coverage', 'The premium payment', 'The underwriting process'], correctIndex: 1, rationale: 'A rider is an amendment or attachment to the policy that modifies or adds to the coverage, often for an additional premium.' },
  { id: 12, category: 'Life Insurance Basics', question: 'Which rider allows the insured to purchase additional coverage without evidence of insurability?', options: ['Waiver of premium', 'Accidental death benefit', 'Guaranteed insurability rider', 'Payor benefit rider'], correctIndex: 2, rationale: 'The guaranteed insurability rider allows the policyholder to purchase additional coverage at specified future dates without proving insurability.' },
  { id: 13, category: 'Life Insurance Basics', question: 'What does the "waiver of premium" rider do?', options: ['Waives the death benefit', 'Waives premium payments if the insured becomes disabled', 'Doubles the death benefit', 'Reduces the face amount'], correctIndex: 1, rationale: 'The waiver of premium rider waives premium payments if the insured becomes totally disabled, keeping the policy in force without payment.' },
  { id: 14, category: 'Life Insurance Basics', question: 'What is "term conversion"?', options: ['Converting cash value to term insurance', 'Converting a term policy to a permanent policy without evidence of insurability', 'Converting a group policy to individual', 'Extending the term period'], correctIndex: 1, rationale: 'Term conversion allows the policyholder to convert a term life policy to a permanent life policy without proving insurability, usually before a specified deadline.' },
  { id: 15, category: 'Life Insurance Basics', question: 'What is the difference between "participating" and "non-participating" policies?', options: ['Participating requires a medical exam; non-participating does not', 'Participating policies pay dividends; non-participating do not', 'Participating policies have higher death benefits', 'There is no difference'], correctIndex: 1, rationale: 'Participating policies may pay dividends to policyholders from the insurer\'s surplus. Non-participating policies do not pay dividends and typically have lower premiums.' },
  { id: 16, category: 'Life Insurance Basics', question: 'What type of life insurance is typically used for mortgage protection?', options: ['Whole life', 'Decreasing term', 'Universal life', 'Variable life'], correctIndex: 1, rationale: 'Decreasing term insurance is commonly used for mortgage protection because the death benefit decreases over time, mirroring the declining mortgage balance.' },
  { id: 17, category: 'Life Insurance Basics', question: 'What is "group life insurance"?', options: ['A policy covering multiple unrelated individuals', 'A single policy covering a group of people, typically through an employer', 'Life insurance for families only', 'A type of whole life insurance'], correctIndex: 1, rationale: 'Group life insurance is a single policy issued to an employer or organization that covers a group of members, usually without individual underwriting.' },
  { id: 18, category: 'Life Insurance Basics', question: 'In universal life insurance, what are the two types of death benefit options?', options: ['Fixed and variable', 'Option A (level) and Option B (increasing)', 'Short-term and long-term', 'Guaranteed and non-guaranteed'], correctIndex: 1, rationale: 'Universal life offers Option A (level death benefit) where cash value is included in the face amount, and Option B (increasing) where cash value is added on top of the face amount.' },
  { id: 19, category: 'Life Insurance Basics', question: 'What is the "free-look period" for a newly purchased life insurance policy?', options: ['5 days', '10 days', '30 days', '60 days'], correctIndex: 1, rationale: 'The free-look period is typically 10 days (varies by state) during which the policy owner can return a newly purchased policy for a full refund of premiums paid.' },
  { id: 20, category: 'Life Insurance Basics', question: 'What is "insurable interest"?', options: ['Interest earned on cash value', 'The financial stake one person has in another\'s continued life', 'The interest rate on a policy loan', 'The rate of return on investments'], correctIndex: 1, rationale: 'Insurable interest means one party would suffer a financial loss from the death of the insured. It must exist at the time of application for life insurance.' },
  { id: 21, category: 'Life Insurance Basics', question: 'Which type of insurance provides the MOST coverage for the LEAST premium?', options: ['Whole life', 'Universal life', 'Term life', 'Variable universal life'], correctIndex: 2, rationale: 'Term life insurance provides the most coverage (highest death benefit) for the lowest premium because it has no cash value component and covers only a specified period.' },
  { id: 22, category: 'Life Insurance Basics', question: 'What is a "Modified Endowment Contract" (MEC)?', options: ['A whole life policy with reduced premiums', 'A life insurance policy that has been funded with too much premium relative to the death benefit', 'A type of term insurance', 'An annuity contract'], correctIndex: 1, rationale: 'A MEC is a life insurance policy that has been overfunded beyond IRS limits (fails the 7-pay test), causing it to lose certain tax advantages on distributions.' },
  { id: 23, category: 'Life Insurance Basics', question: 'What does "nonforfeiture" mean in life insurance?', options: ['The policy cannot be cancelled', 'Options that allow a policyholder to access accumulated cash value if they stop paying premiums', 'The death benefit cannot be reduced', 'The premium cannot increase'], correctIndex: 1, rationale: 'Nonforfeiture options (cash surrender, reduced paid-up, extended term) protect a policyholder\'s right to the cash value they\'ve built up if they can no longer pay premiums.' },
  { id: 24, category: 'Life Insurance Basics', question: 'What is the "contestability period"?', options: ['The time period during which an insured can contest premium amounts', 'Usually 2 years from policy issue during which the insurer can void the policy for misrepresentation', 'The time to file a claim', 'The grace period for premiums'], correctIndex: 1, rationale: 'The contestability period is typically 2 years from policy issuance during which the insurer can investigate and void the policy for material misrepresentation on the application.' },
  { id: 25, category: 'Life Insurance Basics', question: 'What is the purpose of the "suicide clause" in life insurance?', options: ['To exclude all self-inflicted injuries', 'To limit the insurer\'s liability if the insured commits suicide within the first 2 years', 'To deny claims for dangerous activities', 'To increase premiums for mental health conditions'], correctIndex: 1, rationale: 'The suicide clause states that if the insured dies by suicide within the first 2 years of the policy, the insurer will only refund premiums paid rather than pay the death benefit.' },

  // ═══════════════════════════════════════
  // HEALTH INSURANCE BASICS (25 questions)
  // ═══════════════════════════════════════
  { id: 26, category: 'Health Insurance Basics', question: 'What is a "deductible" in health insurance?', options: ['The monthly premium payment', 'The amount the insured must pay out-of-pocket before insurance begins paying', 'The copayment for doctor visits', 'The maximum the insurer will pay'], correctIndex: 1, rationale: 'A deductible is the amount of covered expenses the insured must pay out-of-pocket before the insurance company starts paying benefits.' },
  { id: 27, category: 'Health Insurance Basics', question: 'What does "coinsurance" mean?', options: ['Two insurance policies covering the same risk', 'The percentage of covered costs shared between the insurer and insured after the deductible', 'Insurance provided by two companies', 'The cost of reinsurance'], correctIndex: 1, rationale: 'Coinsurance is the percentage split of costs between insurer and insured after the deductible is met. For example, 80/20 means the insurer pays 80% and the insured pays 20%.' },
  { id: 28, category: 'Health Insurance Basics', question: 'What is an HMO?', options: ['High Maintenance Organization', 'Health Maintenance Organization', 'Hospital Medical Office', 'Health Medical Oversight'], correctIndex: 1, rationale: 'An HMO (Health Maintenance Organization) is a type of managed care plan that requires members to use a network of providers and get referrals from a primary care physician for specialist visits.' },
  { id: 29, category: 'Health Insurance Basics', question: 'What is a PPO?', options: ['Primary Provider Organization', 'Preferred Provider Organization', 'Professional Physician Organization', 'Premium Payment Option'], correctIndex: 1, rationale: 'A PPO (Preferred Provider Organization) allows members to see any provider but pays higher benefits when using in-network providers. No referrals are needed for specialists.' },
  { id: 30, category: 'Health Insurance Basics', question: 'What is COBRA?', options: ['A type of health insurance plan', 'A federal law that allows employees to continue group health coverage after leaving employment', 'A state health program', 'A Medicare supplement'], correctIndex: 1, rationale: 'COBRA (Consolidated Omnibus Budget Reconciliation Act) allows employees who lose their group health insurance to continue coverage for up to 18-36 months at their own expense.' },
  { id: 31, category: 'Health Insurance Basics', question: 'How long can COBRA coverage last for a qualifying event of termination?', options: ['12 months', '18 months', '24 months', '36 months'], correctIndex: 1, rationale: 'For termination of employment or reduction in hours, COBRA coverage lasts up to 18 months. For other qualifying events like death or divorce, it can last up to 36 months.' },
  { id: 32, category: 'Health Insurance Basics', question: 'What is the "elimination period" in disability insurance?', options: ['The time before the policy takes effect', 'The waiting period after disability begins before benefits are paid', 'The time to process a claim', 'The period coverage is eliminated'], correctIndex: 1, rationale: 'The elimination period is the waiting period between when a disability occurs and when benefit payments begin. Common elimination periods are 30, 60, 90, or 180 days.' },
  { id: 33, category: 'Health Insurance Basics', question: 'What is the difference between "own occupation" and "any occupation" disability?', options: ['There is no difference', '"Own occupation" pays if you can\'t do YOUR job; "any occupation" pays only if you can\'t do ANY job', '"Own occupation" is cheaper', '"Any occupation" has shorter elimination periods'], correctIndex: 1, rationale: '"Own occupation" disability considers you disabled if you cannot perform the duties of YOUR specific occupation. "Any occupation" only considers you disabled if you cannot perform ANY job.' },
  { id: 34, category: 'Health Insurance Basics', question: 'Medicare Part A covers:', options: ['Prescription drugs', 'Doctor visits', 'Hospital inpatient care', 'Dental and vision'], correctIndex: 2, rationale: 'Medicare Part A covers hospital inpatient care, skilled nursing facility care, hospice care, and some home health care. It is premium-free for most people who paid Medicare taxes.' },
  { id: 35, category: 'Health Insurance Basics', question: 'Medicare Part B covers:', options: ['Hospital stays', 'Outpatient medical services and doctor visits', 'Prescription drugs', 'Long-term care'], correctIndex: 1, rationale: 'Medicare Part B covers outpatient medical services including doctor visits, preventive services, durable medical equipment, and some home health services. It requires a monthly premium.' },
  { id: 36, category: 'Health Insurance Basics', question: 'Medicare Part D covers:', options: ['Dental care', 'Doctor visits', 'Prescription drugs', 'Hospital stays'], correctIndex: 2, rationale: 'Medicare Part D provides prescription drug coverage through private insurance plans approved by Medicare. It requires a separate premium.' },
  { id: 37, category: 'Health Insurance Basics', question: 'At what age are most people eligible for Medicare?', options: ['55', '60', '62', '65'], correctIndex: 3, rationale: 'Most people become eligible for Medicare at age 65. People under 65 may qualify if they have certain disabilities or End-Stage Renal Disease (ESRD).' },
  { id: 38, category: 'Health Insurance Basics', question: 'What is a Medicare Supplement (Medigap) policy?', options: ['A replacement for Medicare', 'Private insurance that helps pay for costs not covered by Original Medicare', 'A government program', 'The same as Medicare Advantage'], correctIndex: 1, rationale: 'Medigap policies are sold by private companies and help pay for healthcare costs not covered by Original Medicare, such as copayments, coinsurance, and deductibles.' },
  { id: 39, category: 'Health Insurance Basics', question: 'What is "long-term care insurance"?', options: ['Insurance for hospital stays over 30 days', 'Insurance that covers custodial and skilled nursing care for extended periods', 'Medicare Part A extended coverage', 'Disability insurance for seniors'], correctIndex: 1, rationale: 'Long-term care insurance covers services like nursing home care, assisted living, home health aides, and adult daycare that are not typically covered by health insurance or Medicare.' },
  { id: 40, category: 'Health Insurance Basics', question: 'What does "pre-existing condition" mean?', options: ['A condition that may develop in the future', 'A health condition that existed before coverage began', 'A genetic predisposition to illness', 'A condition from a workplace injury'], correctIndex: 1, rationale: 'A pre-existing condition is a health condition that was diagnosed or treated before coverage began. Under the ACA, health insurers cannot deny coverage or charge more for pre-existing conditions.' },
  { id: 41, category: 'Health Insurance Basics', question: 'Under the ACA, dependents can remain on their parents\' health plan until age:', options: ['21', '23', '25', '26'], correctIndex: 3, rationale: 'The Affordable Care Act (ACA) requires health plans that cover dependents to allow them to remain on their parents\' plan until age 26, regardless of student status or financial dependence.' },
  { id: 42, category: 'Health Insurance Basics', question: 'What is an HSA (Health Savings Account)?', options: ['A type of health insurance', 'A tax-advantaged account used with a high-deductible health plan to pay for qualified medical expenses', 'A government healthcare program', 'A retirement account'], correctIndex: 1, rationale: 'An HSA is a tax-advantaged savings account paired with a high-deductible health plan (HDHP). Contributions are tax-deductible, growth is tax-free, and withdrawals for qualified medical expenses are tax-free.' },
  { id: 43, category: 'Health Insurance Basics', question: 'What is "coordination of benefits"?', options: ['Combining two policies into one', 'A provision to prevent duplicate payments when a person is covered by more than one plan', 'Coordinating care between doctors', 'Transferring benefits to another person'], correctIndex: 1, rationale: 'Coordination of benefits prevents overpayment when someone has coverage under two or more plans by determining which plan pays first (primary) and which pays second (secondary).' },
  { id: 44, category: 'Health Insurance Basics', question: 'What is an "out-of-pocket maximum"?', options: ['The highest premium allowed', 'The most an insured has to pay for covered services in a plan year', 'The maximum the insurance company will pay', 'The deductible amount'], correctIndex: 1, rationale: 'The out-of-pocket maximum is the most an insured person will pay for covered services in a policy period. After reaching this amount, the plan pays 100% of covered benefits.' },
  { id: 45, category: 'Health Insurance Basics', question: 'What is a "copayment" (copay)?', options: ['The insured\'s share of coinsurance', 'A fixed amount paid by the insured for a covered service at the time of service', 'The monthly premium', 'The deductible amount'], correctIndex: 1, rationale: 'A copayment is a fixed dollar amount (e.g., $25) that the insured pays at the time a covered service is received, such as a doctor visit or prescription.' },
  { id: 46, category: 'Health Insurance Basics', question: 'Medicaid is a program for:', options: ['People over 65', 'Low-income individuals and families', 'Military veterans', 'Government employees'], correctIndex: 1, rationale: 'Medicaid is a joint federal-state program that provides health coverage to low-income individuals and families who meet eligibility requirements set by each state.' },
  { id: 47, category: 'Health Insurance Basics', question: 'What is the "open enrollment period" for health insurance?', options: ['Any time during the year', 'A specific time each year when individuals can enroll in or change health coverage', 'The first month of employment', 'The month of January only'], correctIndex: 1, rationale: 'The open enrollment period is a specific annual window during which individuals can enroll in, switch, or drop health insurance coverage. Outside this period, enrollment requires a qualifying life event.' },
  { id: 48, category: 'Health Insurance Basics', question: 'What is a "qualifying life event" for health insurance enrollment?', options: ['Getting a raise at work', 'A major life change such as marriage, birth of a child, or job loss that triggers a special enrollment period', 'Turning 30', 'Moving to a new house in the same state'], correctIndex: 1, rationale: 'A qualifying life event (marriage, divorce, birth, adoption, job loss, moving to new state) triggers a Special Enrollment Period allowing changes to health coverage outside open enrollment.' },
  { id: 49, category: 'Health Insurance Basics', question: 'What type of health policy pays a fixed dollar amount per day of hospitalization?', options: ['Major medical', 'Hospital indemnity', 'PPO plan', 'HMO plan'], correctIndex: 1, rationale: 'Hospital indemnity insurance pays a fixed daily, weekly, or monthly benefit for each day of hospitalization, regardless of actual hospital charges.' },
  { id: 50, category: 'Health Insurance Basics', question: 'Which of the following is NOT covered by Medicare?', options: ['Inpatient hospital care', 'Doctor visits', 'Long-term custodial care', 'Outpatient surgery'], correctIndex: 2, rationale: 'Medicare does not cover long-term custodial care (help with daily activities like bathing, dressing). This is a common reason people purchase long-term care insurance.' },

  // ═══════════════════════════════════════
  // POLICY PROVISIONS (25 questions)
  // ═══════════════════════════════════════
  { id: 51, category: 'Policy Provisions', question: 'What is the "entire contract" provision?', options: ['The policy plus the application constitute the entire contract', 'Only the policy document matters', 'The contract includes verbal agreements', 'The provision allows modifications without consent'], correctIndex: 0, rationale: 'The entire contract provision states that the policy and the attached application together form the complete contract. No external documents can modify it, and the insurer cannot reference outside material.' },
  { id: 52, category: 'Policy Provisions', question: 'What is the "incontestability clause"?', options: ['The insurer can contest the policy at any time', 'After a specified period (usually 2 years), the insurer cannot void the policy except for nonpayment of premiums', 'The policyholder cannot contest claim denials', 'The clause allows unlimited contestability'], correctIndex: 1, rationale: 'After the contestability period (usually 2 years), the insurer cannot void or rescind the policy for misrepresentation in the application, except for nonpayment of premiums or fraud.' },
  { id: 53, category: 'Policy Provisions', question: 'What is the "misstatement of age" provision?', options: ['The policy is voided if age is misstated', 'Benefits are adjusted to reflect what the premium would have purchased at the correct age', 'The policy is cancelled and premiums refunded', 'Premium is doubled as penalty'], correctIndex: 1, rationale: 'If the insured\'s age is misstated, the death benefit will be adjusted to the amount the premium would have purchased at the correct age, rather than voiding the policy.' },
  { id: 54, category: 'Policy Provisions', question: 'What is "assignment" of a life insurance policy?', options: ['Naming a beneficiary', 'Transferring ownership rights of the policy to another party', 'Cancelling the policy', 'Changing the insured'], correctIndex: 1, rationale: 'Assignment is the transfer of some or all ownership rights to another party. An absolute assignment transfers all rights; a collateral assignment transfers rights as security for a loan.' },
  { id: 55, category: 'Policy Provisions', question: 'What is the "reinstatement" provision?', options: ['Starting a new policy', 'Allows a lapsed policy to be restored under certain conditions', 'Reinstating a cancelled claim', 'Restoring reduced benefits'], correctIndex: 1, rationale: 'Reinstatement allows a policyholder to restore a lapsed policy, typically within 3-5 years, by paying back premiums with interest and providing evidence of insurability.' },
  { id: 56, category: 'Policy Provisions', question: 'What is the "settlement options" provision?', options: ['Options for settling disputes', 'The different ways death benefit proceeds can be paid to beneficiaries', 'Options for surrendering the policy', 'Options for premium payment'], correctIndex: 1, rationale: 'Settlement options are the methods by which death benefit proceeds can be paid: lump sum, fixed period, fixed amount, life income, or interest only.' },
  { id: 57, category: 'Policy Provisions', question: 'What is a "policy loan"?', options: ['A loan to buy a policy', 'A loan taken from the policy\'s cash value', 'A bank loan secured by the policy', 'A loan from the insurance company for premiums'], correctIndex: 1, rationale: 'A policy loan allows the policyholder to borrow against the policy\'s cash value. Interest is charged, and unpaid loans reduce the death benefit.' },
  { id: 58, category: 'Policy Provisions', question: 'If a policyholder dies with an outstanding policy loan, what happens?', options: ['The loan is forgiven', 'The loan amount plus interest is deducted from the death benefit', 'The beneficiary must repay the loan separately', 'The policy is voided'], correctIndex: 1, rationale: 'If the insured dies with an outstanding policy loan, the loan balance plus accrued interest is deducted from the death benefit before payment to the beneficiary.' },
  { id: 59, category: 'Policy Provisions', question: 'What is "automatic premium loan" provision?', options: ['Automatically increases premiums', 'Uses available cash value to pay overdue premiums to prevent lapse', 'Automatically takes out a bank loan', 'Increases the death benefit'], correctIndex: 1, rationale: 'The automatic premium loan provision automatically uses the policy\'s available cash value to pay any overdue premiums, preventing the policy from lapsing.' },
  { id: 60, category: 'Policy Provisions', question: 'What are the three standard nonforfeiture options?', options: ['Lump sum, annuity, interest only', 'Cash surrender value, reduced paid-up insurance, extended term insurance', 'Return of premium, death benefit, dividend', 'Fixed, variable, indexed'], correctIndex: 1, rationale: 'The three nonforfeiture options are: cash surrender (receive the cash value), reduced paid-up (a smaller paid-up policy), and extended term (same face amount for a limited period).' },
  { id: 61, category: 'Policy Provisions', question: 'What is "spendthrift clause"?', options: ['A clause that limits spending on premiums', 'A provision that protects policy proceeds from the beneficiary\'s creditors', 'A clause requiring minimum spending', 'A premium discount clause'], correctIndex: 1, rationale: 'The spendthrift clause protects policy proceeds from claims by the beneficiary\'s creditors, ensuring the death benefit reaches the intended beneficiary.' },
  { id: 62, category: 'Policy Provisions', question: 'What is "subrogation"?', options: ['Substituting one beneficiary for another', 'The insurer\'s right to recover from a third party who caused the loss', 'Subordinating one policy to another', 'Subletting a policy'], correctIndex: 1, rationale: 'Subrogation is the insurer\'s right to pursue a third party that caused the insured\'s loss, to recover the amount the insurer paid on the claim.' },
  { id: 63, category: 'Policy Provisions', question: 'What does the "grace period" typically last for life insurance?', options: ['10 days', '14 days', '30-31 days', '60 days'], correctIndex: 2, rationale: 'The grace period for life insurance is typically 30 or 31 days after the premium due date. If the insured dies during the grace period, the death benefit is still paid minus the overdue premium.' },
  { id: 64, category: 'Policy Provisions', question: 'An "irrevocable beneficiary" means:', options: ['The beneficiary can be changed at any time', 'The beneficiary designation cannot be changed without the beneficiary\'s consent', 'The beneficiary is always the estate', 'The beneficiary must be a family member'], correctIndex: 1, rationale: 'An irrevocable beneficiary cannot be changed without that beneficiary\'s written consent. This gives the beneficiary a vested interest in the policy.' },
  { id: 65, category: 'Policy Provisions', question: 'What is "accelerated death benefit"?', options: ['A faster claims process', 'A provision allowing early payment of part of the death benefit if the insured is terminally ill', 'An increased death benefit', 'A benefit paid for accidental death'], correctIndex: 1, rationale: 'The accelerated death benefit (or living benefit) allows a terminally ill insured to receive a portion of the death benefit while still alive, typically if diagnosed with less than 12-24 months to live.' },
  { id: 66, category: 'Policy Provisions', question: 'In health insurance, what is the "mandatory provisions" requirement?', options: ['Provisions that the policyholder must follow', 'Provisions that must be included in all individual health insurance policies by state law', 'Provisions mandated by the federal government only', 'Provisions relating to mandatory enrollment'], correctIndex: 1, rationale: 'Mandatory provisions are those that state law requires to be included in all individual health insurance policies, such as grace period, reinstatement, and claims procedures.' },
  { id: 67, category: 'Policy Provisions', question: 'What is the "time limit on certain defenses" provision in health insurance?', options: ['Limits the time to file a lawsuit', 'After 2-3 years, the insurer cannot deny claims based on pre-existing conditions or misrepresentation (except fraud)', 'Limits the defense period for claims', 'Sets a time limit for appeals'], correctIndex: 1, rationale: 'Similar to the incontestability clause in life insurance, this health insurance provision prevents the insurer from denying claims based on pre-existing conditions or misrepresentation after 2-3 years.' },
  { id: 68, category: 'Policy Provisions', question: 'What is "proof of loss" in insurance?', options: ['Proof that the loss did not occur', 'Documentation the insured must provide to support a claim', 'Proof the insurer paid the claim', 'Proof of premium payment'], correctIndex: 1, rationale: 'Proof of loss is the documentation the insured must submit to the insurer to support an insurance claim. In health insurance, this must typically be filed within 90 days of the loss.' },
  { id: 69, category: 'Policy Provisions', question: 'What is the standard time frame to file a proof of loss in health insurance?', options: ['30 days', '60 days', '90 days', '1 year'], correctIndex: 2, rationale: 'Health insurance policies require proof of loss to be filed within 90 days of the date of loss, though late filing is accepted if it was not reasonably possible to file on time.' },
  { id: 70, category: 'Policy Provisions', question: 'How long does the insurer have to pay a claim after receiving proof of loss?', options: ['Immediately', '30 days', '60 days', '90 days'], correctIndex: 0, rationale: 'The insurer must pay claims "immediately" upon receipt of due proof of loss. In practice, this means as soon as reasonably possible, typically within 30-60 days.' },
  { id: 71, category: 'Policy Provisions', question: 'What is a "common disaster" clause?', options: ['Coverage for natural disasters', 'A provision addressing what happens when both the insured and beneficiary die in the same event', 'Coverage for multiple claims', 'A clause about epidemic coverage'], correctIndex: 1, rationale: 'The common disaster clause addresses the scenario where both the insured and primary beneficiary die in the same event. It typically provides that the insured is presumed to have survived the beneficiary.' },
  { id: 72, category: 'Policy Provisions', question: 'What is "per capita" beneficiary distribution?', options: ['Equal distribution among living beneficiaries', 'Distribution per family branch', 'Distribution to the estate', 'Distribution based on age'], correctIndex: 0, rationale: 'Per capita distribution means the death benefit is divided equally among surviving beneficiaries. If one dies, their share is split among the remaining living beneficiaries.' },
  { id: 73, category: 'Policy Provisions', question: 'What is "per stirpes" beneficiary distribution?', options: ['Equal distribution to all beneficiaries', 'Distribution by family branch — a deceased beneficiary\'s share goes to their descendants', 'Distribution to the oldest beneficiary', 'Distribution to the estate'], correctIndex: 1, rationale: 'Per stirpes distribution means each family branch receives an equal share. If a beneficiary predeceases the insured, that beneficiary\'s share passes to their children/descendants.' },
  { id: 74, category: 'Policy Provisions', question: 'What is the "legal actions" provision in health insurance?', options: ['The insurer can take legal action at any time', 'The insured cannot sue until 60 days after filing proof of loss and must sue within 3 years', 'Legal action is prohibited', 'The insured must sue within 30 days'], correctIndex: 1, rationale: 'The legal actions provision states the insured cannot sue until 60 days after proof of loss is filed (to give the insurer time to process) and must bring action within 3 years of the loss date.' },
  { id: 75, category: 'Policy Provisions', question: 'What is an "exclusion" in an insurance policy?', options: ['Additional coverage added', 'A specific condition, circumstance, or situation that the policy will NOT cover', 'A premium discount', 'An optional rider'], correctIndex: 1, rationale: 'An exclusion is a specific condition, hazard, or circumstance listed in the policy that is not covered. Common exclusions include war, self-inflicted injuries, and certain hazardous activities.' },

  // ═══════════════════════════════════════
  // ANNUITIES (25 questions)
  // ═══════════════════════════════════════
  { id: 76, category: 'Annuities', question: 'What is an annuity?', options: ['A type of life insurance', 'A contract that provides regular income payments, typically for retirement', 'A health insurance supplement', 'A savings account'], correctIndex: 1, rationale: 'An annuity is a contract between an individual and an insurance company designed to provide a stream of income payments, typically during retirement.' },
  { id: 77, category: 'Annuities', question: 'What is the "accumulation period" of an annuity?', options: ['The time during which annuity payments are received', 'The period during which premiums are paid and the annuity value grows', 'The waiting period before benefits begin', 'The period after the annuity expires'], correctIndex: 1, rationale: 'The accumulation period (or pay-in period) is the time during which the annuity owner makes payments and the account value grows tax-deferred before annuitization.' },
  { id: 78, category: 'Annuities', question: 'What is the "annuitization" phase?', options: ['Purchasing the annuity', 'The period during which the annuity is converted into a stream of periodic payments', 'Surrendering the annuity', 'Transferring the annuity'], correctIndex: 1, rationale: 'Annuitization is when the accumulated value is converted into a series of periodic income payments. Once annuitized, the payments are typically irrevocable.' },
  { id: 79, category: 'Annuities', question: 'What is a "fixed annuity"?', options: ['An annuity with variable returns', 'An annuity that guarantees a minimum interest rate and fixed payments', 'An annuity invested in stocks', 'An annuity with no guarantees'], correctIndex: 1, rationale: 'A fixed annuity provides a guaranteed minimum interest rate during the accumulation period and fixed periodic payments during the payout phase. The insurance company bears the investment risk.' },
  { id: 80, category: 'Annuities', question: 'What is a "variable annuity"?', options: ['An annuity with a guaranteed rate', 'An annuity where the value and payments vary based on the performance of underlying investments', 'An annuity with fixed payments', 'A type of fixed-indexed annuity'], correctIndex: 1, rationale: 'A variable annuity allows the owner to invest in subaccounts (similar to mutual funds). The value and payments fluctuate based on investment performance. The owner bears the investment risk.' },
  { id: 81, category: 'Annuities', question: 'What is a "fixed-indexed annuity" (FIA)?', options: ['Same as a fixed annuity', 'An annuity that earns interest based on a stock market index with a guaranteed minimum', 'A variable annuity', 'An annuity invested directly in index funds'], correctIndex: 1, rationale: 'A fixed-indexed annuity earns interest based on the performance of a market index (like S&P 500) with a guaranteed minimum (floor) and a maximum cap rate. The principal is protected from market losses.' },
  { id: 82, category: 'Annuities', question: 'What is a "surrender charge"?', options: ['A fee for purchasing an annuity', 'A penalty charged for withdrawing funds before the surrender period expires', 'The cost of the annuity', 'A charge for changing beneficiaries'], correctIndex: 1, rationale: 'A surrender charge is a fee imposed when annuity funds are withdrawn during the surrender period (typically 5-10 years). The charge usually decreases each year.' },
  { id: 83, category: 'Annuities', question: 'What annuity payout option provides income for as long as the annuitant lives?', options: ['Period certain', 'Life only (straight life)', 'Lump sum', 'Fixed period'], correctIndex: 1, rationale: 'A life only (straight life) annuity provides payments for the annuitant\'s entire lifetime. Payments stop at death with no remaining value to beneficiaries, providing the highest periodic payment.' },
  { id: 84, category: 'Annuities', question: 'What is a "life with period certain" annuity?', options: ['Payments for life with a guaranteed minimum period — if the annuitant dies during the period, payments continue to a beneficiary', 'Payments only during the certain period', 'Payments for a fixed number of years', 'The same as straight life'], correctIndex: 0, rationale: 'Life with period certain guarantees payments for the annuitant\'s life, but if death occurs within the "certain" period (e.g., 10 or 20 years), a beneficiary receives payments for the remainder.' },
  { id: 85, category: 'Annuities', question: 'What is a "joint and survivor" annuity?', options: ['An annuity owned by two companies', 'An annuity that provides payments for the lifetimes of two people', 'An annuity with two accumulation periods', 'An annuity that doubles payments'], correctIndex: 1, rationale: 'A joint and survivor annuity covers two lives and continues payments (in full or a percentage) after the first annuitant dies until the second annuitant also dies.' },
  { id: 86, category: 'Annuities', question: 'What is the penalty for early withdrawal from an annuity before age 59½?', options: ['5% penalty', '10% IRS penalty plus ordinary income tax', '15% penalty', 'No penalty'], correctIndex: 1, rationale: 'Withdrawals from an annuity before age 59½ are subject to a 10% IRS early withdrawal penalty on the earnings portion, in addition to ordinary income tax on the gains.' },
  { id: 87, category: 'Annuities', question: 'How are annuity withdrawals taxed (non-qualified)?', options: ['All withdrawals are tax-free', 'Earnings come out first and are taxed as ordinary income (LIFO)', 'All withdrawals are taxed as capital gains', 'Only the principal is taxed'], correctIndex: 1, rationale: 'Non-qualified annuity withdrawals follow LIFO (Last In, First Out) — earnings are withdrawn first and taxed as ordinary income. The original premium (basis) is withdrawn tax-free after earnings are exhausted.' },
  { id: 88, category: 'Annuities', question: 'What is a "deferred annuity"?', options: ['An annuity that starts payments immediately', 'An annuity where income payments begin at a future date', 'An annuity with deferred premiums', 'An annuity that has been postponed'], correctIndex: 1, rationale: 'A deferred annuity delays income payments to a future date, allowing the invested funds to grow tax-deferred during the accumulation period before payouts begin.' },
  { id: 89, category: 'Annuities', question: 'What is an "immediate annuity"?', options: ['An annuity that starts income payments within one payment period (usually 30 days) after purchase', 'An annuity purchased instantly', 'An annuity with no surrender period', 'An annuity that matures immediately'], correctIndex: 0, rationale: 'An immediate annuity begins income payments within one annuity period (typically within 30 days) after a single lump-sum premium is paid. It has no accumulation period.' },
  { id: 90, category: 'Annuities', question: 'What is a "1035 exchange"?', options: ['A type of annuity', 'A tax-free exchange of one insurance or annuity contract for another', 'A withdrawal without penalty', 'A loan against an annuity'], correctIndex: 1, rationale: 'A 1035 exchange (IRS Section 1035) allows the tax-free transfer of funds from one life insurance or annuity contract to another without triggering a taxable event.' },
  { id: 91, category: 'Annuities', question: 'In a 1035 exchange, a life insurance policy can be exchanged for:', options: ['Only another life insurance policy', 'Another life insurance policy or an annuity', 'Only an annuity', 'A health insurance policy'], correctIndex: 1, rationale: 'Under Section 1035, a life insurance policy can be exchanged tax-free for another life policy or an annuity. However, an annuity cannot be exchanged for a life insurance policy.' },
  { id: 92, category: 'Annuities', question: 'What is the "exclusion ratio" in annuity taxation?', options: ['The ratio of excluded beneficiaries', 'The formula that determines what portion of each annuity payment is non-taxable return of premium', 'The ratio of excluded investments', 'The tax exclusion percentage'], correctIndex: 1, rationale: 'The exclusion ratio determines what portion of each annuity payment represents a tax-free return of premium (basis) vs. taxable earnings. It is calculated as investment / expected return.' },
  { id: 93, category: 'Annuities', question: 'Who bears the investment risk in a variable annuity?', options: ['The insurance company', 'The annuity owner (contract holder)', 'The government', 'The beneficiary'], correctIndex: 1, rationale: 'In a variable annuity, the contract holder bears the investment risk because payments are based on the performance of the underlying investments (subaccounts).' },
  { id: 94, category: 'Annuities', question: 'Who bears the investment risk in a fixed annuity?', options: ['The annuity owner', 'The insurance company', 'The government', 'Both parties equally'], correctIndex: 1, rationale: 'In a fixed annuity, the insurance company bears the investment risk because it guarantees a minimum interest rate and fixed payments regardless of its investment performance.' },
  { id: 95, category: 'Annuities', question: 'Variable annuities are regulated by:', options: ['State insurance departments only', 'Both the SEC and state insurance departments', 'The IRS only', 'No regulatory body'], correctIndex: 1, rationale: 'Variable annuities are considered securities and are regulated by both the SEC (Securities and Exchange Commission) and state insurance departments. Agents must have securities and insurance licenses.' },
  { id: 96, category: 'Annuities', question: 'What is a "single premium" annuity?', options: ['An annuity with one low payment', 'An annuity funded with one lump-sum payment', 'An annuity with monthly premiums', 'The cheapest annuity available'], correctIndex: 1, rationale: 'A single premium annuity is funded with one lump-sum payment. It can be either immediate (payments start right away) or deferred (payments start later).' },
  { id: 97, category: 'Annuities', question: 'What is a "flexible premium" annuity?', options: ['An annuity with fixed premiums', 'An annuity that allows the owner to vary the amount and timing of premium payments', 'An annuity that adjusts premiums based on market', 'A type of immediate annuity'], correctIndex: 1, rationale: 'A flexible premium annuity allows the owner to make premium payments of varying amounts at varying intervals, providing flexibility in funding the annuity.' },
  { id: 98, category: 'Annuities', question: 'What is the "free withdrawal" provision in annuities?', options: ['All withdrawals are free', 'Allows a specified percentage (typically 10%) to be withdrawn annually without surrender charges', 'Withdrawals are free after the first year', 'The annuity can be cancelled for free'], correctIndex: 1, rationale: 'Most annuities allow a free withdrawal of a specified percentage (commonly 10%) of the account value each year without incurring surrender charges.' },
  { id: 99, category: 'Annuities', question: 'What happens to an annuity when the owner dies during the accumulation period?', options: ['The annuity is forfeited', 'The beneficiary receives the accumulated value (or minimum guaranteed amount)', 'The insurance company keeps all funds', 'The annuity converts to life insurance'], correctIndex: 1, rationale: 'If the annuity owner dies during accumulation, the named beneficiary receives either the current account value or the total premiums paid, whichever is greater (death benefit guarantee).' },
  { id: 100, category: 'Annuities', question: 'What is a "qualified annuity"?', options: ['An annuity that has been approved by the state', 'An annuity funded with pre-tax dollars through a qualified retirement plan', 'An annuity with the highest ratings', 'An annuity sold by a qualified agent'], correctIndex: 1, rationale: 'A qualified annuity is purchased with pre-tax dollars within a qualified retirement plan (IRA, 401k). All withdrawals are taxed as ordinary income since no taxes were paid on contributions.' },

  // ═══════════════════════════════════════
  // FEDERAL TAX (25 questions)
  // ═══════════════════════════════════════
  { id: 101, category: 'Federal Tax', question: 'Are life insurance death benefit proceeds generally taxable?', options: ['Yes, always', 'No, death benefits are generally received income tax-free', 'Only if over $100,000', 'Only for whole life policies'], correctIndex: 1, rationale: 'Life insurance death benefit proceeds are generally received income tax-free by the beneficiary under IRC Section 101(a). However, they may be subject to estate tax if the insured had ownership incidents.' },
  { id: 102, category: 'Federal Tax', question: 'How is the cash value growth in a life insurance policy taxed?', options: ['Taxed annually', 'Tax-deferred — not taxed until withdrawn', 'Tax-free always', 'Taxed as capital gains'], correctIndex: 1, rationale: 'Cash value growth inside a life insurance policy accumulates tax-deferred. Taxes are only due on gains if and when they are withdrawn (on amounts exceeding the cost basis).' },
  { id: 103, category: 'Federal Tax', question: 'What is the tax treatment of dividends from a participating life insurance policy?', options: ['Always taxable as income', 'Considered a return of premium and generally not taxable unless they exceed total premiums paid', 'Taxed as capital gains', 'Tax-free always'], correctIndex: 1, rationale: 'Policy dividends are generally treated as a return of premium (overpayment) and are not taxable until the total dividends received exceed the total premiums paid into the policy.' },
  { id: 104, category: 'Federal Tax', question: 'If a life insurance policy is surrendered for its cash value, what is taxable?', options: ['The entire cash value', 'Only the gain — the amount exceeding total premiums paid (cost basis)', 'Nothing is taxable', 'Only the first $10,000'], correctIndex: 1, rationale: 'When a policy is surrendered, the gain (cash value received minus total premiums paid/cost basis) is taxed as ordinary income. If the cash value is less than premiums paid, there is no taxable gain.' },
  { id: 105, category: 'Federal Tax', question: 'What is the tax treatment of employer-paid group life insurance over $50,000?', options: ['Completely tax-free', 'The cost of coverage over $50,000 is taxable income to the employee', 'Fully taxable', 'Tax-deductible for the employee'], correctIndex: 1, rationale: 'Employer-provided group life insurance is tax-free for the first $50,000 of coverage. The imputed cost of coverage over $50,000 (based on IRS Table I rates) is taxable income to the employee.' },
  { id: 106, category: 'Federal Tax', question: 'Are premiums paid for personal life insurance tax-deductible?', options: ['Yes, always', 'Only for term insurance', 'No, personal life insurance premiums are not tax-deductible', 'Only if itemized'], correctIndex: 2, rationale: 'Premiums paid for personal life insurance are not tax-deductible. This is a trade-off for the death benefit being received income tax-free by the beneficiary.' },
  { id: 107, category: 'Federal Tax', question: 'What is the "transfer for value" rule?', options: ['A rule about transferring policies between states', 'If a life insurance policy is transferred for valuable consideration, the death benefit may become partially taxable', 'A rule about transferring cash value', 'A rule about dividend transfers'], correctIndex: 1, rationale: 'If a life insurance policy is sold or transferred for valuable consideration, the death benefit loses its tax-free status. The recipient would owe income tax on the benefit minus the purchase price and premiums paid.' },
  { id: 108, category: 'Federal Tax', question: 'What is the "7-pay test" for life insurance?', options: ['A test requiring 7 premium payments', 'A test to determine if a life insurance policy is a Modified Endowment Contract (MEC)', 'A 7-year waiting period', 'A test of 7 policy features'], correctIndex: 1, rationale: 'The 7-pay test determines if a policy becomes a MEC. If cumulative premiums paid in the first 7 years exceed the net level premium needed to pay up the policy in 7 years, it becomes a MEC.' },
  { id: 109, category: 'Federal Tax', question: 'How are withdrawals from a Modified Endowment Contract (MEC) taxed?', options: ['Tax-free like regular life insurance', 'Gains come out first and are taxed as ordinary income (LIFO), plus a 10% penalty if under 59½', 'Taxed as capital gains', 'Only the basis is taxed'], correctIndex: 1, rationale: 'MEC withdrawals follow LIFO — gains are withdrawn first and taxed as ordinary income. A 10% penalty applies on gains if the owner is under 59½, similar to annuity taxation.' },
  { id: 110, category: 'Federal Tax', question: 'Are health insurance benefits received by an individual generally taxable?', options: ['Yes, always', 'No, health insurance benefits are generally received tax-free', 'Only if the employer paid the premiums', 'Only for amounts over $5,000'], correctIndex: 1, rationale: 'Health insurance benefits (reimbursement for medical expenses) are generally received tax-free, regardless of who paid the premiums.' },
  { id: 111, category: 'Federal Tax', question: 'How are disability income benefits taxed when the employee pays the premiums?', options: ['Fully taxable', 'Tax-free because the employee paid with after-tax dollars', 'Partially taxable', 'Taxed as capital gains'], correctIndex: 1, rationale: 'When the employee pays disability insurance premiums with after-tax dollars, the disability income benefits received are tax-free. If the employer pays, benefits are taxable.' },
  { id: 112, category: 'Federal Tax', question: 'How are disability income benefits taxed when the employer pays the premiums?', options: ['Tax-free', 'Taxable as ordinary income to the employee', 'Taxed at capital gains rates', 'Only 50% taxable'], correctIndex: 1, rationale: 'When the employer pays disability insurance premiums, the benefits received by the employee are fully taxable as ordinary income, since the employee didn\'t pay tax on the premiums.' },
  { id: 113, category: 'Federal Tax', question: 'What is the gift tax exclusion for life insurance premium gifts?', options: ['$5,000', '$10,000', 'The annual gift tax exclusion amount (currently $18,000 per recipient)', '$50,000'], correctIndex: 2, rationale: 'Life insurance premiums paid as gifts qualify for the annual gift tax exclusion. The amount is adjusted periodically for inflation (currently $18,000 per recipient per year).' },
  { id: 114, category: 'Federal Tax', question: 'What is an "Irrevocable Life Insurance Trust" (ILIT)?', options: ['A trust that can be changed at any time', 'A trust designed to own a life insurance policy to keep the death benefit out of the insured\'s taxable estate', 'A type of life insurance policy', 'A trust for minor beneficiaries only'], correctIndex: 1, rationale: 'An ILIT is a trust that owns a life insurance policy. Because the insured has no ownership incidents, the death benefit is excluded from their taxable estate, providing estate tax benefits.' },
  { id: 115, category: 'Federal Tax', question: 'Are long-term care insurance premiums tax-deductible?', options: ['No, never', 'Yes, qualified LTC premiums are deductible as medical expenses subject to age-based limits', 'Only for employer-paid plans', 'Only for self-employed individuals'], correctIndex: 1, rationale: 'Qualified long-term care insurance premiums are deductible as medical expenses subject to age-based limits set by the IRS, and the overall AGI threshold for medical expense deductions.' },
  { id: 116, category: 'Federal Tax', question: 'Are long-term care insurance benefits taxable?', options: ['Always taxable', 'Generally tax-free up to a per diem limit set by the IRS', 'Taxed as ordinary income', 'Taxed as capital gains'], correctIndex: 1, rationale: 'Qualified long-term care benefits are generally received tax-free. Per diem plans have a daily limit set by the IRS; amounts exceeding the limit or actual costs may be taxable.' },
  { id: 117, category: 'Federal Tax', question: 'What is a "viatical settlement"?', options: ['Settling an insurance dispute', 'The sale of a life insurance policy by a terminally ill person to a third party for less than the death benefit', 'A type of annuity payout', 'An estate planning tool'], correctIndex: 1, rationale: 'A viatical settlement involves a terminally ill person selling their life insurance policy to a third party for more than the cash value but less than the death benefit. Proceeds are generally tax-free for the terminally ill seller.' },
  { id: 118, category: 'Federal Tax', question: 'What is a "life settlement"?', options: ['Same as a viatical settlement', 'The sale of a life insurance policy by someone who is NOT terminally ill, typically an older policyholder', 'Settling a life insurance claim', 'A settlement option'], correctIndex: 1, rationale: 'A life settlement is similar to a viatical settlement but involves a seller who is not terminally or chronically ill. Proceeds may be partially taxable to the seller.' },
  { id: 119, category: 'Federal Tax', question: 'How are policy loans taxed in a non-MEC life insurance policy?', options: ['Taxed as ordinary income', 'Generally not taxable as long as the policy remains in force', 'Taxed as capital gains', 'Always taxable'], correctIndex: 1, rationale: 'Policy loans from a non-MEC life insurance policy are generally not considered taxable income as long as the policy remains in force. If the policy lapses with an outstanding loan, the gain becomes taxable.' },
  { id: 120, category: 'Federal Tax', question: 'What is "Section 162" (executive bonus) plan?', options: ['A qualified retirement plan', 'An arrangement where the employer pays life insurance premiums as a tax-deductible bonus to a key employee', 'A tax code for health insurance', 'A section about annuity taxation'], correctIndex: 1, rationale: 'A Section 162 executive bonus plan allows employers to pay life insurance premiums for key employees as a tax-deductible bonus. The bonus is taxable income to the employee.' },
  { id: 121, category: 'Federal Tax', question: 'What is "key person" (key employee) life insurance?', options: ['Insurance for all employees', 'Life insurance purchased by a business on the life of a key employee to protect against financial loss', 'Personal insurance for executives', 'Group life insurance'], correctIndex: 1, rationale: 'Key person insurance is owned by and payable to the business. It compensates the company for financial losses resulting from the death of a key employee or executive.' },
  { id: 122, category: 'Federal Tax', question: 'Are premiums for key person life insurance tax-deductible for the business?', options: ['Yes, always', 'No, premiums are not tax-deductible', 'Only for C-corporations', 'Only up to $50,000'], correctIndex: 1, rationale: 'Premiums paid for key person life insurance are NOT tax-deductible for the business. However, the death benefit received by the business is generally income tax-free.' },
  { id: 123, category: 'Federal Tax', question: 'What is a "buy-sell agreement" funded by life insurance?', options: ['An agreement to buy and sell policies', 'A legally binding agreement that uses life insurance to fund the purchase of a deceased owner\'s business interest', 'A sales agreement for the insurance company', 'An agreement between agent and client'], correctIndex: 1, rationale: 'A buy-sell agreement funded by life insurance ensures that when a business owner dies, the death benefit provides funds for the surviving owners (or the business) to purchase the deceased\'s share.' },
  { id: 124, category: 'Federal Tax', question: 'In a "cross-purchase" buy-sell agreement, who owns the policies?', options: ['The business entity', 'Each owner purchases and owns a policy on the life of every other owner', 'The insurance company', 'A trust'], correctIndex: 1, rationale: 'In a cross-purchase agreement, each business owner buys a policy on every other owner\'s life. When an owner dies, the surviving owners use the death benefits to purchase the deceased\'s share.' },
  { id: 125, category: 'Federal Tax', question: 'In an "entity purchase" (stock redemption) buy-sell agreement, who owns the policies?', options: ['Individual owners', 'The business entity itself owns policies on each owner\'s life', 'The bank', 'The IRS'], correctIndex: 1, rationale: 'In an entity purchase agreement, the business entity owns and pays premiums on life insurance policies covering each owner. When an owner dies, the business uses the proceeds to buy back their interest.' },

  // ═══════════════════════════════════════
  // QUALIFIED PLANS (25 questions)
  // ═══════════════════════════════════════
  { id: 126, category: 'Qualified Plans', question: 'What makes a retirement plan "qualified"?', options: ['It is sold by a qualified agent', 'It meets IRS requirements under ERISA for tax-advantaged treatment', 'It is approved by the state', 'It has been in existence for at least 5 years'], correctIndex: 1, rationale: 'A qualified plan meets specific IRS and ERISA requirements, which allows tax-deductible contributions, tax-deferred growth, and penalties for early withdrawal before age 59½.' },
  { id: 127, category: 'Qualified Plans', question: 'What is a "Traditional IRA"?', options: ['An employer-sponsored plan', 'An individual retirement account with tax-deductible contributions and tax-deferred growth', 'A type of annuity', 'A health savings account'], correctIndex: 1, rationale: 'A Traditional IRA allows individuals to make tax-deductible contributions (subject to income limits if covered by an employer plan). Growth is tax-deferred, and withdrawals are taxed as ordinary income.' },
  { id: 128, category: 'Qualified Plans', question: 'What is a "Roth IRA"?', options: ['An employer plan', 'An IRA funded with after-tax dollars where qualified withdrawals are tax-free', 'A type of pension', 'A pre-tax savings account'], correctIndex: 1, rationale: 'A Roth IRA is funded with after-tax dollars (no tax deduction for contributions). Qualified withdrawals (after age 59½ and 5-year holding period) are completely tax-free, including earnings.' },
  { id: 129, category: 'Qualified Plans', question: 'What is the penalty for early withdrawal from a Traditional IRA before age 59½?', options: ['5%', '10%', '15%', '25%'], correctIndex: 1, rationale: 'Early withdrawals from a Traditional IRA before age 59½ are subject to a 10% penalty tax in addition to ordinary income tax, unless an exception applies (disability, first home, etc.).' },
  { id: 130, category: 'Qualified Plans', question: 'At what age must Required Minimum Distributions (RMDs) begin from a Traditional IRA?', options: ['59½', '65', '70½', '73'], correctIndex: 3, rationale: 'Under the SECURE 2.0 Act, Required Minimum Distributions from Traditional IRAs must begin by April 1 of the year following the year the owner turns 73.' },
  { id: 131, category: 'Qualified Plans', question: 'Do Roth IRAs have Required Minimum Distributions (RMDs) during the owner\'s lifetime?', options: ['Yes, same as Traditional IRA', 'No, Roth IRAs have no RMDs during the owner\'s lifetime', 'Only after age 75', 'Only for large balances'], correctIndex: 1, rationale: 'Roth IRAs do not have Required Minimum Distributions during the owner\'s lifetime, making them excellent estate planning tools.' },
  { id: 132, category: 'Qualified Plans', question: 'What is a "401(k) plan"?', options: ['A government pension', 'An employer-sponsored defined contribution plan where employees can defer pre-tax salary', 'A type of IRA', 'A health insurance plan'], correctIndex: 1, rationale: 'A 401(k) is an employer-sponsored defined contribution retirement plan that allows employees to contribute pre-tax salary (or Roth after-tax). Employers may also make matching contributions.' },
  { id: 133, category: 'Qualified Plans', question: 'What is a "defined benefit plan"?', options: ['A plan where the employee defines how much to contribute', 'A pension plan that promises a specific benefit amount at retirement based on salary and years of service', 'A 401(k) plan', 'A profit-sharing plan'], correctIndex: 1, rationale: 'A defined benefit plan (pension) promises a specific retirement benefit calculated by a formula typically based on salary history and years of service. The employer bears the investment risk.' },
  { id: 134, category: 'Qualified Plans', question: 'What is a "defined contribution plan"?', options: ['A pension plan', 'A plan where contributions are defined but the retirement benefit depends on investment performance', 'A plan with guaranteed benefits', 'A government retirement plan'], correctIndex: 1, rationale: 'In a defined contribution plan (like 401k, 403b), contributions are specified but the eventual benefit depends on the account\'s investment performance. The employee bears the investment risk.' },
  { id: 135, category: 'Qualified Plans', question: 'What is a "403(b) plan"?', options: ['A plan for private companies', 'A tax-sheltered annuity plan for employees of public schools and tax-exempt organizations', 'A type of pension', 'A plan for government employees'], correctIndex: 1, rationale: 'A 403(b) plan (Tax-Sheltered Annuity) is available to employees of public schools, colleges, and certain tax-exempt organizations. It works similarly to a 401(k).' },
  { id: 136, category: 'Qualified Plans', question: 'What is a "SEP IRA"?', options: ['A personal IRA', 'A Simplified Employee Pension plan where the employer makes contributions to employees\' IRAs', 'A type of 401(k)', 'A government plan'], correctIndex: 1, rationale: 'A SEP (Simplified Employee Pension) IRA allows employers, including self-employed individuals, to make tax-deductible contributions to employees\' IRA accounts. Only the employer contributes.' },
  { id: 137, category: 'Qualified Plans', question: 'What is a "SIMPLE IRA"?', options: ['A basic IRA with no rules', 'A Savings Incentive Match Plan for Employees for small businesses with 100 or fewer employees', 'A simplified version of a 401(k)', 'A children\'s savings plan'], correctIndex: 1, rationale: 'A SIMPLE (Savings Incentive Match Plan for Employees) IRA is designed for small businesses with 100 or fewer employees. Both employer and employee can contribute.' },
  { id: 138, category: 'Qualified Plans', question: 'What is "vesting"?', options: ['Buying a vest', 'The process by which an employee earns the right to employer contributions over time', 'Investing in the stock market', 'The application process'], correctIndex: 1, rationale: 'Vesting determines when an employee gains full ownership of employer contributions. Cliff vesting means full ownership after a set period; graded vesting gradually increases ownership over time.' },
  { id: 139, category: 'Qualified Plans', question: 'What is a "rollover" in retirement planning?', options: ['Changing investment options', 'Moving retirement funds from one qualified plan to another without triggering taxes', 'Rolling over premiums to next year', 'Converting an IRA to a 401k'], correctIndex: 1, rationale: 'A rollover is the tax-free transfer of funds from one retirement plan to another (e.g., 401k to IRA). Direct rollovers avoid mandatory withholding; indirect rollovers must be completed within 60 days.' },
  { id: 140, category: 'Qualified Plans', question: 'What is a "profit-sharing plan"?', options: ['A plan where employees share in the company\'s profits through employer contributions to a retirement account', 'A plan where employees share tips', 'A type of pension plan', 'A bonus program'], correctIndex: 0, rationale: 'A profit-sharing plan is a defined contribution plan where the employer makes discretionary contributions to employees\' accounts based on company profits. Contributions are not mandatory each year.' },
  { id: 141, category: 'Qualified Plans', question: 'What is the "catch-up contribution" provision?', options: ['Making up missed contributions from prior years', 'Additional contributions allowed for participants aged 50 and older', 'Contributing to catch up to the employer match', 'Catching up on RMDs'], correctIndex: 1, rationale: 'Catch-up contributions allow plan participants aged 50 and older to make additional contributions above the standard annual limit, helping them save more as they approach retirement.' },
  { id: 142, category: 'Qualified Plans', question: 'What is ERISA?', options: ['A type of IRA', 'The Employee Retirement Income Security Act — a federal law that sets minimum standards for retirement plans', 'A state insurance regulation', 'An insurance company'], correctIndex: 1, rationale: 'ERISA (Employee Retirement Income Security Act of 1974) is a federal law that sets minimum standards for most voluntarily established retirement and health plans to protect plan participants.' },
  { id: 143, category: 'Qualified Plans', question: 'What is a "Keogh plan"?', options: ['An IRA for minors', 'A qualified retirement plan for self-employed individuals and unincorporated businesses', 'A government pension', 'A type of 403(b)'], correctIndex: 1, rationale: 'A Keogh (HR-10) plan is a tax-deferred retirement plan for self-employed individuals or unincorporated businesses. It can be structured as a defined benefit or defined contribution plan.' },
  { id: 144, category: 'Qualified Plans', question: 'What is a "457 plan"?', options: ['A plan for private sector employees', 'A deferred compensation plan for state and local government employees and some non-profit organizations', 'A type of pension', 'A military retirement plan'], correctIndex: 1, rationale: 'A 457(b) plan is a deferred compensation retirement plan available to state and local government employees and certain non-profit employees. It does not have a 10% early withdrawal penalty.' },
  { id: 145, category: 'Qualified Plans', question: 'What is the "fiduciary" standard in retirement plans?', options: ['A suggestion to act in good faith', 'A legal obligation for plan administrators to act in the best interest of plan participants', 'A standard for insurance agents', 'A requirement for plan documentation'], correctIndex: 1, rationale: 'Under ERISA, a fiduciary is legally required to act solely in the best interest of plan participants, manage the plan prudently, diversify investments, and follow plan documents.' },
  { id: 146, category: 'Qualified Plans', question: 'Can you convert a Traditional IRA to a Roth IRA?', options: ['No, conversions are not allowed', 'Yes, but you must pay income tax on the converted amount', 'Yes, with no tax consequences', 'Only if you are under 50'], correctIndex: 1, rationale: 'You can convert a Traditional IRA to a Roth IRA at any time, but the converted amount is treated as taxable income in the year of conversion. There is no 10% early withdrawal penalty on conversions.' },
  { id: 147, category: 'Qualified Plans', question: 'What is a "non-qualified" retirement plan?', options: ['A plan that fails IRS testing', 'A retirement plan that does not meet IRS/ERISA requirements and does not receive the same tax benefits', 'An illegal retirement plan', 'A plan with no contributions'], correctIndex: 1, rationale: 'Non-qualified plans don\'t meet ERISA requirements, so they don\'t receive tax-deductible contributions. However, they offer more flexibility and can discriminate in favor of certain employees.' },
  { id: 148, category: 'Qualified Plans', question: 'What is a "deferred compensation" plan?', options: ['A plan that defers retirement', 'An arrangement where a portion of an employee\'s compensation is set aside to be paid at a future date', 'A delayed insurance premium', 'A loan against retirement funds'], correctIndex: 1, rationale: 'Deferred compensation plans allow employees to defer a portion of their income to a future date (typically retirement), deferring taxation until the income is received.' },
  { id: 149, category: 'Qualified Plans', question: 'What is the "nondiscrimination" requirement for qualified plans?', options: ['Plans must not discriminate by age', 'Plans cannot disproportionately favor highly compensated employees in contributions or benefits', 'Plans must offer the same investments to all', 'Plans must accept all applicants'], correctIndex: 1, rationale: 'Qualified plans must satisfy nondiscrimination testing to ensure they do not disproportionately benefit highly compensated employees. This ensures broad participation and fair treatment.' },
  { id: 150, category: 'Qualified Plans', question: 'What is a "hardship withdrawal" from a 401(k)?', options: ['Any withdrawal before retirement', 'A withdrawal permitted for an immediate and heavy financial need, subject to taxes and potentially a 10% penalty', 'A penalty-free withdrawal', 'A withdrawal during a recession'], correctIndex: 1, rationale: 'A hardship withdrawal allows 401(k) participants to withdraw funds for immediate, heavy financial needs (medical expenses, home purchase, tuition). The withdrawal is taxable and may incur a 10% penalty.' },

  // ═══════════════════════════════════════
  // STATE REGULATIONS (25 questions)
  // ═══════════════════════════════════════
  { id: 151, category: 'State Regulations', question: 'Who regulates the insurance industry in each state?', options: ['The federal government', 'The State Department of Insurance (DOI) or Commissioner of Insurance', 'The SEC', 'The IRS'], correctIndex: 1, rationale: 'Each state regulates its own insurance industry through its Department of Insurance (DOI) headed by a Commissioner or Superintendent of Insurance.' },
  { id: 152, category: 'State Regulations', question: 'What is the purpose of state insurance regulations?', options: ['To generate revenue for the state', 'To protect consumers, ensure solvency of insurers, and maintain fair market practices', 'To limit the number of insurance companies', 'To set insurance prices'], correctIndex: 1, rationale: 'State insurance regulations exist to protect the public by ensuring insurers remain financially solvent, requiring fair trade practices, and preventing unfair or deceptive acts.' },
  { id: 153, category: 'State Regulations', question: 'What is an insurance producer license?', options: ['A license to manufacture insurance products', 'A license that authorizes an individual to sell, solicit, or negotiate insurance', 'A license for insurance companies', 'A license for adjusters only'], correctIndex: 1, rationale: 'An insurance producer license (formerly called an agent/broker license) authorizes an individual to sell, solicit, or negotiate insurance contracts in the licensed state.' },
  { id: 154, category: 'State Regulations', question: 'What is "continuing education" (CE) for insurance agents?', options: ['Initial licensing education', 'Required ongoing education that licensed agents must complete to maintain their license', 'College courses for insurance majors', 'Optional training'], correctIndex: 1, rationale: 'Continuing education requirements ensure licensed agents stay current with industry changes, laws, and regulations. The number of hours and topics required varies by state.' },
  { id: 155, category: 'State Regulations', question: 'What is "twisting" in insurance?', options: ['A valid sales technique', 'The illegal practice of using misrepresentation to convince a policyholder to lapse an existing policy to buy a new one', 'Changing policy provisions', 'Combining multiple policies'], correctIndex: 1, rationale: 'Twisting is an illegal and unethical practice where an agent uses misrepresentation or incomplete information to induce a policyholder to drop an existing policy in favor of purchasing a new one.' },
  { id: 156, category: 'State Regulations', question: 'What is "churning" in insurance?', options: ['Processing claims quickly', 'The illegal practice of replacing policies primarily to generate commissions', 'Reviewing policies annually', 'Customer retention activities'], correctIndex: 1, rationale: 'Churning involves an agent replacing a client\'s existing insurance policies with new ones primarily to earn new commissions, without benefit to the policyholder. It is illegal.' },
  { id: 157, category: 'State Regulations', question: 'What is "rebating" in insurance?', options: ['Getting a refund on premiums', 'The illegal practice of offering something of value not specified in the policy as an inducement to purchase', 'Premium discounts', 'Rebating policy dividends'], correctIndex: 1, rationale: 'Rebating is the illegal practice of giving the client a portion of the agent\'s commission or anything of value not specified in the policy contract as an incentive to buy. Most states prohibit this.' },
  { id: 158, category: 'State Regulations', question: 'What is "misrepresentation" in insurance?', options: ['Accurate policy descriptions', 'Making false or misleading statements about a policy to induce a purchase', 'A minor error in paperwork', 'Changing a policy name'], correctIndex: 1, rationale: 'Misrepresentation is making false, deceptive, or misleading statements about the terms, benefits, or conditions of a policy. It is illegal and can result in license revocation.' },
  { id: 159, category: 'State Regulations', question: 'What is a "guaranty association" or "guaranty fund"?', options: ['A guarantee of profit for agents', 'A state-mandated fund that protects policyholders if an insurance company becomes insolvent', 'A federal insurance program', 'A type of reinsurance'], correctIndex: 1, rationale: 'State guaranty associations protect policyholders when an insurance company becomes insolvent. All licensed insurers contribute to the fund, which pays claims up to specified limits.' },
  { id: 160, category: 'State Regulations', question: 'What is "unfair discrimination" in insurance?', options: ['All forms of risk classification', 'Treating similarly situated individuals differently based on characteristics not related to risk', 'Offering different products', 'Using actuarial data'], correctIndex: 1, rationale: 'Unfair discrimination means treating individuals in the same risk class differently (different premiums or coverage) based on factors not related to the risk, such as race, religion, or gender (where prohibited).' },
  { id: 161, category: 'State Regulations', question: 'What is "replacement" of a life insurance policy?', options: ['Adding a rider', 'When new insurance is purchased and existing coverage is surrendered, lapsed, or otherwise terminated', 'Renewing an existing policy', 'Upgrading coverage'], correctIndex: 1, rationale: 'Replacement occurs when new insurance is purchased and, in connection with the sale, existing coverage is lapsed, surrendered, converted, or otherwise terminated. States have specific replacement regulations.' },
  { id: 162, category: 'State Regulations', question: 'What must an agent do when replacing an existing policy?', options: ['Nothing special', 'Provide the client with a replacement notice and comparison of existing vs. new policy', 'Just sell the new policy', 'Contact the old insurer to cancel'], correctIndex: 1, rationale: 'When replacing a policy, agents must provide the client with a written replacement notice, compare the old and new policies, and notify the existing insurer. These regulations protect consumers from unsuitable replacements.' },
  { id: 163, category: 'State Regulations', question: 'What is the "free-look period" for insurance policies?', options: ['A period to look at the policy for free', 'A period after delivery during which the policyholder can return the policy for a full refund', 'The underwriting review period', 'The claims review period'], correctIndex: 1, rationale: 'The free-look period (typically 10-30 days depending on the state and product) allows the policyholder to review a newly delivered policy and return it for a full refund if not satisfied.' },
  { id: 164, category: 'State Regulations', question: 'What is "suitability" in insurance sales?', options: ['Whether the product looks good', 'The requirement that recommended products must be appropriate for the client\'s financial situation and needs', 'Whether the agent is suitable', 'Product availability'], correctIndex: 1, rationale: 'Suitability requires that agents recommend products that are appropriate for the client based on their financial situation, objectives, and needs. This is especially important for annuity sales.' },
  { id: 165, category: 'State Regulations', question: 'What is "defamation" in insurance regulation?', options: ['Promoting your own company', 'Making false and damaging statements about a competitor or their products', 'Advertising insurance products', 'Criticizing insurance regulations'], correctIndex: 1, rationale: 'Defamation in insurance is making maliciously false statements about a competing insurer\'s financial condition or business practices. It is an unfair trade practice and is prohibited.' },
  { id: 166, category: 'State Regulations', question: 'What is "coercion" in insurance?', options: ['Encouraging someone to buy insurance', 'Using threats, intimidation, or force to compel someone to buy or maintain insurance', 'A sales technique', 'Mandatory insurance'], correctIndex: 1, rationale: 'Coercion is the illegal practice of using threats, intimidation, or force to compel someone to purchase or not to surrender insurance. It is an unfair trade practice.' },
  { id: 167, category: 'State Regulations', question: 'What is a "surplus lines" insurer?', options: ['An insurer with extra capital', 'A non-admitted insurer that provides coverage for risks that admitted insurers are unwilling to cover', 'An insurer with surplus policies', 'A reinsurance company'], correctIndex: 1, rationale: 'Surplus lines insurers are non-admitted (not licensed in the state) but are allowed to write coverage for risks that the admitted market cannot or will not cover. They are regulated differently.' },
  { id: 168, category: 'State Regulations', question: 'What is the McCarran-Ferguson Act?', options: ['A state insurance law', 'A federal law that grants states the primary authority to regulate the insurance industry', 'A law establishing the SEC', 'A healthcare act'], correctIndex: 1, rationale: 'The McCarran-Ferguson Act (1945) established that states, not the federal government, have the primary authority to regulate the insurance industry, as long as state regulation is adequate.' },
  { id: 169, category: 'State Regulations', question: 'What is "controlled business"?', options: ['Business regulated by the government', 'Insurance sold primarily to oneself, family, or business associates — which many states limit', 'A type of business insurance', 'Insurance for corporations'], correctIndex: 1, rationale: 'Controlled business refers to insurance coverage written primarily on the producer\'s own life, family members, or business associates. Many states limit or prohibit licensing solely for writing controlled business.' },
  { id: 170, category: 'State Regulations', question: 'What can cause an insurance license to be revoked?', options: ['Selling too many policies', 'Fraud, misrepresentation, felony conviction, or violations of insurance laws', 'Having too many clients', 'Changing companies'], correctIndex: 1, rationale: 'Grounds for license revocation include fraud, misrepresentation, conviction of a felony, violation of insurance laws, twisting, churning, rebating, and other unfair trade practices.' },
  { id: 171, category: 'State Regulations', question: 'What is an "admitted" insurance company?', options: ['A company that admits to being an insurer', 'An insurer that is licensed and authorized to do business in a state, subject to state regulations', 'Any insurance company', 'A company admitted to the stock exchange'], correctIndex: 1, rationale: 'An admitted (or authorized) insurer is one that has been granted a license by the state to conduct insurance business. It must comply with all state regulations and is backed by the state guaranty fund.' },
  { id: 172, category: 'State Regulations', question: 'What is "prior approval" rate regulation?', options: ['Approval before an agent can sell', 'Insurers must get state approval for rates BEFORE they can be used', 'Approval of policy language only', 'Federal rate approval'], correctIndex: 1, rationale: 'Under prior approval regulation, insurers must submit proposed rates to the state insurance department and receive approval before implementing them. This contrasts with "file and use" regulation.' },
  { id: 173, category: 'State Regulations', question: 'What is the difference between an "agent" and a "broker"?', options: ['There is no difference', 'An agent represents the insurance company; a broker represents the client/insured', 'An agent is licensed; a broker is not', 'An agent sells life; a broker sells health'], correctIndex: 1, rationale: 'An agent is appointed by and represents the insurance company (insurer). A broker represents the insurance buyer (client/insured) and shops among multiple companies for the best coverage and price.' },
  { id: 174, category: 'State Regulations', question: 'What is "apparent authority" of an agent?', options: ['Authority clearly written in the contract', 'Authority that a reasonable person would believe the agent has based on the insurer\'s actions', 'The agent\'s actual authority', 'Authority granted by the state'], correctIndex: 1, rationale: 'Apparent authority is the authority that a third party reasonably believes an agent has based on the insurance company\'s actions, representations, or failure to act, even if not explicitly granted.' },
  { id: 175, category: 'State Regulations', question: 'What is "express authority"?', options: ['Authority implied by the agent\'s role', 'Authority that is specifically granted and written in the agent\'s contract with the insurer', 'Authority to express opinions', 'Authority granted by the client'], correctIndex: 1, rationale: 'Express authority is the specific, written authority granted to an agent through their agency contract with the insurance company. It explicitly defines what the agent is authorized to do.' },

  // ═══════════════════════════════════════
  // ETHICS & LAW (25 questions)
  // ═══════════════════════════════════════
  { id: 176, category: 'Ethics & Law', question: 'What is a "fiduciary duty" in insurance?', options: ['A duty to maximize sales', 'A duty to act in the best interest of the client with honesty, trust, and good faith', 'A duty to the insurance company only', 'A duty to follow all advertising rules'], correctIndex: 1, rationale: 'Fiduciary duty requires agents to act in the best interest of their clients, with honesty, good faith, and loyalty. This includes full disclosure and avoiding conflicts of interest.' },
  { id: 177, category: 'Ethics & Law', question: 'What is the "duty of good faith and fair dealing"?', options: ['Being nice to customers', 'An implied obligation in every insurance contract for both parties to act honestly and fairly', 'A sales obligation', 'A requirement for fair pricing only'], correctIndex: 1, rationale: 'The duty of good faith and fair dealing is implied in every insurance contract, requiring both the insurer and insured to act honestly and fairly with each other.' },
  { id: 178, category: 'Ethics & Law', question: 'What constitutes insurance fraud?', options: ['Filing a legitimate claim', 'Any intentional act of deception committed to obtain an unauthorized insurance benefit', 'Making an error on an application', 'Switching insurance companies'], correctIndex: 1, rationale: 'Insurance fraud is any deliberate deception committed for financial gain in an insurance transaction. It includes false claims, inflating damages, staging accidents, and application fraud.' },
  { id: 179, category: 'Ethics & Law', question: 'What is "utmost good faith" (uberrimae fidei)?', options: ['Normal business conduct', 'The principle that both parties to an insurance contract must act with complete honesty and disclosure', 'Good faith in sales only', 'Faith in the insurance system'], correctIndex: 1, rationale: 'Utmost good faith means both the insurer and insured must deal with complete honesty and full disclosure. The applicant must disclose all material facts, and the insurer must clearly explain the coverage.' },
  { id: 180, category: 'Ethics & Law', question: 'What is a "material misrepresentation"?', options: ['Any false statement', 'A false statement significant enough that it would have changed the underwriting decision', 'A minor error on an application', 'A difference of opinion about coverage'], correctIndex: 1, rationale: 'A material misrepresentation is a false statement on an application that is significant enough that, had the truth been known, the insurer would have made a different underwriting decision (denied or rated differently).' },
  { id: 181, category: 'Ethics & Law', question: 'What is "concealment" in insurance?', options: ['Hiding the policy', 'Intentionally withholding material information from the insurer', 'Concealing policy benefits from clients', 'A privacy practice'], correctIndex: 1, rationale: 'Concealment is the intentional failure to disclose material information on an insurance application. Like misrepresentation, it can void the policy if discovered during the contestability period.' },
  { id: 182, category: 'Ethics & Law', question: 'What is the "principle of indemnity"?', options: ['The insured should profit from a loss', 'The insured should be restored to the same financial position as before the loss, no more and no less', 'The insurer should maximize payouts', 'All losses should be fully covered'], correctIndex: 1, rationale: 'The principle of indemnity states insurance should restore the insured to their pre-loss financial position without profit. This prevents moral hazard and is fundamental to property and health insurance.' },
  { id: 183, category: 'Ethics & Law', question: 'What is the "law of large numbers"?', options: ['A law limiting policy numbers', 'The statistical principle that as the number of exposure units increases, actual results approach expected results', 'A law about large insurance companies', 'A requirement for group insurance'], correctIndex: 1, rationale: 'The law of large numbers states that as the number of similar exposure units increases, actual loss experience approaches the expected loss. This is the mathematical foundation of insurance pricing.' },
  { id: 184, category: 'Ethics & Law', question: 'What is an "adhesion" contract?', options: ['A negotiated contract', 'A contract drafted by one party (the insurer) that the other party (the insured) must accept or reject in its entirety', 'A contract that sticks to standard rules', 'A renewable contract'], correctIndex: 1, rationale: 'Insurance policies are adhesion contracts — written by the insurer and accepted or rejected as-is by the applicant. Because of this, any ambiguities are interpreted in favor of the insured.' },
  { id: 185, category: 'Ethics & Law', question: 'What is an "aleatory" contract?', options: ['A contract between two agents', 'A contract where the values exchanged are unequal and depend on an uncertain event', 'A standard business contract', 'A fixed-value contract'], correctIndex: 1, rationale: 'An aleatory contract involves unequal exchanges that depend on chance. In insurance, the policyholder may pay far less in premiums than the potential death benefit, or may pay more if they outlive the term.' },
  { id: 186, category: 'Ethics & Law', question: 'Insurance contracts are "unilateral." What does this mean?', options: ['Both parties make promises', 'Only one party (the insurer) makes a legally enforceable promise — to pay claims', 'The contract is one-sided in favor of the insured', 'The contract cannot be changed'], correctIndex: 1, rationale: 'In a unilateral contract, only the insurer makes a legally binding promise (to pay claims). The policyholder can stop paying premiums at any time without being sued for breach of contract.' },
  { id: 187, category: 'Ethics & Law', question: 'What does "conditional" mean for insurance contracts?', options: ['The contract has no conditions', 'The insurer\'s obligation to pay depends on the insured meeting certain conditions (paying premiums, filing timely claims)', 'The policy is conditioned on market performance', 'Conditions set by the state'], correctIndex: 1, rationale: 'Insurance contracts are conditional because the insurer\'s duty to pay claims depends on the insured meeting certain conditions: paying premiums on time, providing proof of loss, cooperating with investigations.' },
  { id: 188, category: 'Ethics & Law', question: 'What is "adverse selection"?', options: ['Selecting bad investments', 'The tendency for higher-risk individuals to seek insurance more than lower-risk individuals', 'An unfair selection process', 'Selecting against the insurer\'s interests'], correctIndex: 1, rationale: 'Adverse selection is the tendency for people who are more likely to experience a loss to seek insurance coverage. Insurers combat this through underwriting, waiting periods, and exclusions.' },
  { id: 189, category: 'Ethics & Law', question: 'What is "moral hazard"?', options: ['A hazardous moral situation', 'The increased risk of loss due to a person\'s dishonest character or tendency to be careless because insurance exists', 'An ethical insurance practice', 'A type of policy exclusion'], correctIndex: 1, rationale: 'Moral hazard is the risk that a person may act differently (more carelessly or dishonestly) because they have insurance. Example: exaggerating or fabricating a claim because one is insured.' },
  { id: 190, category: 'Ethics & Law', question: 'What is "morale hazard"?', options: ['Same as moral hazard', 'The increased risk of loss due to indifference or carelessness because insurance covers the loss', 'An ethical requirement', 'A type of insurance fraud'], correctIndex: 1, rationale: 'Morale hazard (different from moral hazard) is carelessness or indifference to preventing loss because one has insurance. Unlike moral hazard, it is not intentional dishonesty but rather a lack of concern.' },
  { id: 191, category: 'Ethics & Law', question: 'What is "warranties" vs "representations" in insurance?', options: ['They are the same thing', 'Warranties are guaranteed to be true; representations are believed to be true to the best of one\'s knowledge', 'Warranties are verbal; representations are written', 'Warranties are optional; representations are required'], correctIndex: 1, rationale: 'A warranty is a statement guaranteed to be absolutely true — any breach can void the policy. A representation is a statement believed to be true to the best of the applicant\'s knowledge.' },
  { id: 192, category: 'Ethics & Law', question: 'What is "estoppel" in insurance law?', options: ['Stopping a policy', 'A legal principle preventing a party from asserting a right that contradicts their previous actions or statements', 'Stopping an agent from selling', 'Cancelling a claim'], correctIndex: 1, rationale: 'Estoppel prevents a party from denying something they previously stated or acted upon. If an insurer accepts premiums knowing of a policy violation, it may be estopped from later denying a claim based on that violation.' },
  { id: 193, category: 'Ethics & Law', question: 'What is "waiver" in insurance law?', options: ['Waving goodbye to a client', 'The voluntary relinquishment of a known right by one party', 'A premium discount', 'Waiving the deductible'], correctIndex: 1, rationale: 'A waiver is the voluntary giving up of a known right. If an insurer knowingly waives a policy condition (e.g., accepts late premium), it cannot later use that condition to deny a claim.' },
  { id: 194, category: 'Ethics & Law', question: 'What is "proximate cause"?', options: ['The closest insurance agent', 'The dominant, uninterrupted cause that directly leads to a loss', 'The approximate cost of a loss', 'The first event in a chain of events'], correctIndex: 1, rationale: 'Proximate cause is the dominant cause in an unbroken chain of events that results in a loss. It determines whether a loss is covered — the proximate cause must be a covered peril.' },
  { id: 195, category: 'Ethics & Law', question: 'What privacy law applies to insurance consumers?', options: ['HIPAA only', 'The Gramm-Leach-Bliley Act (GLBA) requires financial institutions, including insurers, to protect consumer financial information', 'No specific law applies', 'The Insurance Privacy Act'], correctIndex: 1, rationale: 'The Gramm-Leach-Bliley Act requires financial institutions (including insurance companies) to explain information-sharing practices and protect customers\' nonpublic personal information.' },
  { id: 196, category: 'Ethics & Law', question: 'What is the "Fair Credit Reporting Act" (FCRA) related to insurance?', options: ['It has no insurance application', 'It regulates how consumer credit information is used in underwriting and requires disclosure if adverse action is taken', 'It sets credit limits for premiums', 'It prevents credit checks'], correctIndex: 1, rationale: 'The FCRA regulates the use of consumer credit information. If an insurer uses credit information to make an adverse underwriting decision, the consumer must be notified and given access to the report.' },
  { id: 197, category: 'Ethics & Law', question: 'What is "E&O" (Errors and Omissions) insurance for agents?', options: ['Coverage for typing errors', 'Professional liability insurance that protects agents against claims of negligence or mistakes in their professional duties', 'Coverage for omitted policy pages', 'A type of health insurance'], correctIndex: 1, rationale: 'E&O insurance protects insurance agents and brokers against claims arising from mistakes, negligence, or failure to perform professional duties, such as providing incorrect advice or failing to procure coverage.' },
  { id: 198, category: 'Ethics & Law', question: 'What is the "doctrine of reasonable expectations"?', options: ['Insurers expect reasonable behavior', 'Ambiguous policy terms are interpreted based on what a reasonable policyholder would expect the coverage to be', 'Agents expect reasonable commissions', 'Policyholders expect reasonable rates'], correctIndex: 1, rationale: 'The doctrine of reasonable expectations holds that insurance coverage should align with what a reasonable policyholder would expect based on the policy language, even if technical policy terms might suggest otherwise.' },
  { id: 199, category: 'Ethics & Law', question: 'What is "bad faith" by an insurer?', options: ['Not being religious', 'Unreasonable denial of a valid claim, failure to investigate, or unfair claims practices by an insurer', 'Making a bad investment', 'Having poor customer service'], correctIndex: 1, rationale: 'Bad faith occurs when an insurer unreasonably denies a valid claim, fails to properly investigate, delays payment without cause, or engages in unfair claims practices. It can result in extra-contractual damages.' },
  { id: 200, category: 'Ethics & Law', question: 'What is the "National Association of Insurance Commissioners" (NAIC)?', options: ['A federal regulatory agency', 'A voluntary organization of state insurance regulators that develops model laws and coordinates regulation', 'An insurance company', 'An agent association'], correctIndex: 1, rationale: 'The NAIC is a voluntary organization of state insurance commissioners that develops model laws and regulations, provides guidance, and coordinates regulatory efforts, but it has no direct regulatory authority.' },

  // ═══════════════════════════════════════
  // LIFE INSURANCE — ADVANCED (13 questions)
  // ═══════════════════════════════════════
  { id: 201, category: 'Life Insurance Basics', question: 'What is "survivorship" (second-to-die) life insurance?', options: ['Insurance on one person\'s life', 'A policy that insures two lives and pays the death benefit only when the second insured dies', 'A policy that pays double on the first death', 'Group insurance for couples'], correctIndex: 1, rationale: 'Survivorship (second-to-die) life insurance covers two people and pays the death benefit only upon the death of the second insured. It is commonly used for estate planning purposes.' },
  { id: 202, category: 'Life Insurance Basics', question: 'What is "first-to-die" life insurance?', options: ['Insurance that pays on the second death', 'A policy covering two or more lives that pays the benefit when the first insured dies', 'Term insurance for young people', 'Accidental death coverage'], correctIndex: 1, rationale: 'First-to-die insurance covers multiple lives under one policy but pays the death benefit upon the first death. It is often used by business partners or married couples for income replacement.' },
  { id: 203, category: 'Life Insurance Basics', question: 'What is "adjustable life insurance"?', options: ['A fixed premium policy', 'A policy that allows the owner to adjust the face amount, premium, and coverage period', 'A policy that automatically adjusts for inflation', 'An employer-adjusted group plan'], correctIndex: 1, rationale: 'Adjustable life insurance allows the policyholder to modify the death benefit, premium amount, and period of protection as their needs change, within certain limits.' },
  { id: 204, category: 'Life Insurance Basics', question: 'What is the "cost of insurance" (COI) in a universal life policy?', options: ['The total premium paid', 'The monthly charge deducted from cash value to pay for the pure death protection', 'The surrender charge', 'The agent\'s commission'], correctIndex: 1, rationale: 'The cost of insurance (COI) is the monthly charge deducted from the cash value to cover the actual cost of the death benefit protection. It increases as the insured ages.' },
  { id: 205, category: 'Life Insurance Basics', question: 'What is a "corridor" in universal life insurance?', options: ['A hallway in the insurance office', 'The minimum required gap between the cash value and the death benefit to maintain tax-favored status', 'A type of policy rider', 'The waiting period'], correctIndex: 1, rationale: 'The corridor is the IRS-required minimum difference between the death benefit and cash value. If cash value grows too close to the death benefit, the policy could become a MEC or lose its tax-favored status.' },
  { id: 206, category: 'Life Insurance Basics', question: 'What is "key person" insurance used for?', options: ['Insuring all employees equally', 'Compensating a business for the financial loss caused by the death of an essential employee', 'Providing group life coverage', 'Funding employee retirement'], correctIndex: 1, rationale: 'Key person insurance is purchased by a business on the life of an essential employee. If that person dies, the death benefit compensates the company for lost revenue, recruitment costs, and business disruption.' },
  { id: 207, category: 'Life Insurance Basics', question: 'What does "paid-up" insurance mean?', options: ['The policy has been cancelled', 'A policy that requires no further premium payments and remains in force', 'A policy with past-due premiums', 'A fully surrendered policy'], correctIndex: 1, rationale: 'A paid-up policy is one where all required premiums have been paid and the policy remains in force for the full death benefit (or reduced amount) without any additional premium payments.' },
  { id: 208, category: 'Life Insurance Basics', question: 'What is "industrial life insurance"?', options: ['Insurance for factories', 'Small face value policies with premiums collected weekly or monthly at the policyholder\'s home', 'Commercial insurance for businesses', 'Workers compensation'], correctIndex: 1, rationale: 'Industrial (debit) life insurance consists of small face value policies (typically under $1,000) with premiums collected weekly or monthly by an agent at the policyholder\'s home or workplace.' },
  { id: 209, category: 'Life Insurance Basics', question: 'What is "credit life insurance"?', options: ['Insurance for credit card companies', 'A policy designed to pay off a borrower\'s remaining debt if they die before the loan is repaid', 'A type of investment product', 'Insurance that improves your credit score'], correctIndex: 1, rationale: 'Credit life insurance is designed to pay off a specific debt (auto loan, mortgage, credit card) if the borrower dies before it is repaid. The creditor is the beneficiary.' },
  { id: 210, category: 'Life Insurance Basics', question: 'What is the difference between "level" and "decreasing" term insurance?', options: ['No difference', 'Level term maintains the same death benefit; decreasing term reduces the death benefit over time', 'Level term is cheaper', 'Decreasing term has higher premiums'], correctIndex: 1, rationale: 'Level term maintains a constant death benefit throughout the term. Decreasing term has a death benefit that gradually reduces over time, commonly used for mortgage protection where the loan balance decreases.' },
  { id: 211, category: 'Life Insurance Basics', question: 'What is "return of premium" (ROP) term insurance?', options: ['A refund of the first premium', 'A term policy that returns all premiums paid if the insured outlives the term', 'A premium discount program', 'A dividend from participating policies'], correctIndex: 1, rationale: 'Return of premium (ROP) term insurance refunds all premiums paid if the insured survives the entire term period. It costs more than standard term but provides a savings element.' },
  { id: 212, category: 'Life Insurance Basics', question: 'What is "annually renewable term" (ART) insurance?', options: ['A one-year non-renewable policy', 'Term insurance that renews each year with increasing premiums based on the insured\'s attained age', 'A type of whole life insurance', 'Annual dividend insurance'], correctIndex: 1, rationale: 'Annually renewable term (ART) provides one-year term coverage that automatically renews each year without evidence of insurability. Premiums increase annually as the insured ages.' },
  { id: 213, category: 'Life Insurance Basics', question: 'In life insurance, what is the "payor benefit" rider?', options: ['A rider that pays the agent', 'A rider that waives premiums on a juvenile policy if the person paying premiums dies or becomes disabled', 'A rider for the policyholder', 'A dividend rider'], correctIndex: 1, rationale: 'The payor benefit rider is attached to juvenile policies. If the person paying premiums (usually a parent) dies or becomes disabled, premiums are waived until the child reaches a specified age.' },

  // ═══════════════════════════════════════
  // HEALTH INSURANCE — ADVANCED (12 questions)
  // ═══════════════════════════════════════
  { id: 214, category: 'Health Insurance Basics', question: 'What is a "POS" (Point of Service) plan?', options: ['A retail insurance plan', 'A managed care plan combining features of HMO and PPO — members choose in-network or out-of-network at the point of service', 'A pharmacy-only plan', 'A government health plan'], correctIndex: 1, rationale: 'A POS plan combines HMO and PPO features. Members can choose to use in-network providers (like an HMO, with lower costs) or go out-of-network (like a PPO, with higher costs) at the point of service.' },
  { id: 215, category: 'Health Insurance Basics', question: 'What is a "high-deductible health plan" (HDHP)?', options: ['A plan with no deductible', 'A health plan with a higher deductible than typical plans, paired with an HSA for tax-advantaged savings', 'An expensive health plan', 'A plan for high-income individuals'], correctIndex: 1, rationale: 'An HDHP has a higher deductible than traditional plans but lower premiums. It qualifies the enrollee to open an HSA. The IRS sets minimum deductible amounts annually.' },
  { id: 216, category: 'Health Insurance Basics', question: 'What is "guaranteed renewability" in health insurance?', options: ['The insurer must renew if the insured pays premiums', 'The policy automatically renews and the insurer cannot cancel except for nonpayment of premium or fraud', 'The insured is guaranteed to never be cancelled', 'The policy renews with lower premiums'], correctIndex: 1, rationale: 'Guaranteed renewable means the insurer must renew the policy as long as premiums are paid on time. The insurer can raise premiums for an entire class of policyholders but cannot single out an individual.' },
  { id: 217, category: 'Health Insurance Basics', question: 'What is "noncancellable" health insurance?', options: ['The policy can never be changed', 'A policy the insurer cannot cancel or raise premiums on as long as premiums are paid on time', 'A policy with no cancellation fee', 'A government-mandated policy'], correctIndex: 1, rationale: 'A noncancellable policy cannot be cancelled by the insurer and premiums cannot be increased as long as the policyholder pays premiums on time. This provides the strongest protection for the insured.' },
  { id: 218, category: 'Health Insurance Basics', question: 'What is "major medical" insurance?', options: ['Coverage for minor illnesses only', 'Comprehensive coverage for serious illness and injury with high maximum benefits, deductibles, and coinsurance', 'Emergency room coverage only', 'Supplemental insurance'], correctIndex: 1, rationale: 'Major medical insurance provides broad, comprehensive coverage for serious illnesses and injuries. It typically has deductibles, coinsurance, and high maximum benefit limits.' },
  { id: 219, category: 'Health Insurance Basics', question: 'What is "stop-loss" insurance in the context of health plans?', options: ['Insurance that stops losses', 'Insurance purchased by self-funded employers to limit their financial exposure from large claims', 'A type of deductible', 'The out-of-pocket maximum'], correctIndex: 1, rationale: 'Stop-loss insurance is purchased by self-funded employers to protect against unexpectedly high claims. Specific stop-loss covers individual claims above a threshold; aggregate stop-loss covers total claims above a threshold.' },
  { id: 220, category: 'Health Insurance Basics', question: 'What is "social insurance"?', options: ['Insurance sold through social media', 'Government-mandated insurance programs like Social Security, Medicare, and unemployment insurance', 'Group insurance through social clubs', 'A private insurance program'], correctIndex: 1, rationale: 'Social insurance refers to government-run programs providing benefits for retirement, disability, healthcare, and unemployment. Examples include Social Security, Medicare, Medicaid, and workers\' compensation.' },
  { id: 221, category: 'Health Insurance Basics', question: 'What is "HIPAA" in relation to health insurance?', options: ['A type of health plan', 'The Health Insurance Portability and Accountability Act — protects health information privacy and ensures portability of coverage', 'A state regulation', 'A Medicare supplement'], correctIndex: 1, rationale: 'HIPAA (1996) protects the privacy and security of personal health information and ensures portability of health coverage when changing jobs. It also limits pre-existing condition exclusions.' },
  { id: 222, category: 'Health Insurance Basics', question: 'What is a "flexible spending account" (FSA)?', options: ['A bank savings account', 'An employer-sponsored account allowing employees to set aside pre-tax dollars for qualified medical or dependent care expenses', 'A retirement account', 'A type of health insurance'], correctIndex: 1, rationale: 'An FSA allows employees to contribute pre-tax dollars for qualified medical expenses or dependent care. Unlike HSAs, FSAs are "use it or lose it" — unused funds may be forfeited at year end.' },
  { id: 223, category: 'Health Insurance Basics', question: 'What is the key difference between an HSA and an FSA?', options: ['There is no difference', 'HSA funds roll over year to year and are owned by the individual; FSA funds may be forfeited and are employer-sponsored', 'FSAs have higher contribution limits', 'HSAs require no qualifying health plan'], correctIndex: 1, rationale: 'HSA funds roll over indefinitely and belong to the individual (portable). FSA funds generally must be used within the plan year or be forfeited. HSAs require an HDHP; FSAs do not.' },
  { id: 224, category: 'Health Insurance Basics', question: 'What is "blanket insurance"?', options: ['Insurance for bedding', 'A single policy covering a group of people without naming each individual, such as a school covering all students', 'A type of umbrella policy', 'Coverage for everything'], correctIndex: 1, rationale: 'Blanket insurance covers a group of people under a single policy without listing them individually. Common examples include coverage for all students at a school or all members of a sports team.' },
  { id: 225, category: 'Health Insurance Basics', question: 'What does "residual disability" mean in disability insurance?', options: ['Complete inability to work', 'A partial disability where the insured can work but at reduced capacity, earning less income than before', 'A disability that has been resolved', 'A disability from a previous policy'], correctIndex: 1, rationale: 'Residual disability means the insured can perform some but not all duties of their occupation, resulting in a loss of income. Benefits are typically proportional to the percentage of income lost.' },

  // ═══════════════════════════════════════
  // POLICY PROVISIONS — ADVANCED (13 questions)
  // ═══════════════════════════════════════
  { id: 226, category: 'Policy Provisions', question: 'What is "collateral assignment" of a life insurance policy?', options: ['Assigning the policy to a family member', 'Temporarily transferring certain policy rights to a lender as security for a loan', 'Permanently transferring ownership', 'Assigning the agent to a new client'], correctIndex: 1, rationale: 'A collateral assignment temporarily transfers some policy rights to a lender as collateral for a loan. When the loan is repaid, the rights revert to the policyholder. The lender can only recover the loan amount from the death benefit.' },
  { id: 227, category: 'Policy Provisions', question: 'What is the "change of beneficiary" provision?', options: ['Beneficiaries can never be changed', 'The policyholder has the right to change the beneficiary at any time (unless the beneficiary is irrevocable)', 'Only the insurer can change the beneficiary', 'The beneficiary changes automatically at renewal'], correctIndex: 1, rationale: 'Unless an irrevocable beneficiary is designated, the policyholder retains the right to change the beneficiary at any time by submitting a written request to the insurer.' },
  { id: 228, category: 'Policy Provisions', question: 'What is the "facility of payment" clause?', options: ['A clause about payment facilities', 'A provision allowing the insurer to pay death benefits to someone other than the named beneficiary if the beneficiary cannot be found or is a minor', 'A premium payment clause', 'A claim processing clause'], correctIndex: 1, rationale: 'The facility of payment clause allows the insurer to pay benefits to a person who has a valid claim (such as someone who paid funeral expenses) when the named beneficiary cannot be located or is legally incapacitated.' },
  { id: 229, category: 'Policy Provisions', question: 'What is the "ownership" provision in life insurance?', options: ['Only the insured can own the policy', 'The policyholder has all rights of ownership including the right to name beneficiaries, assign the policy, and access cash values', 'The insurance company owns the policy', 'Ownership is shared equally'], correctIndex: 1, rationale: 'The owner of a life insurance policy holds all rights: naming and changing beneficiaries, assigning the policy, borrowing against cash value, surrendering the policy, and selecting settlement options.' },
  { id: 230, category: 'Policy Provisions', question: 'What is a "war clause" exclusion?', options: ['Coverage for war veterans', 'An exclusion that denies the death benefit if the insured dies as a result of war or military conflict', 'A clause requiring military service', 'Coverage during wartime'], correctIndex: 1, rationale: 'The war clause excludes coverage for death resulting from war or military conflict. If the insured dies due to war, the insurer typically refunds premiums paid rather than paying the death benefit.' },
  { id: 231, category: 'Policy Provisions', question: 'What is the "aviation exclusion"?', options: ['Coverage for airline passengers', 'An exclusion that may deny benefits if the insured dies while piloting or serving as crew on a private aircraft', 'A rider for frequent flyers', 'No coverage for any air travel'], correctIndex: 1, rationale: 'The aviation exclusion typically excludes death resulting from the insured acting as pilot or crew of a non-commercial aircraft. Deaths as a fare-paying passenger on commercial airlines are generally covered.' },
  { id: 232, category: 'Policy Provisions', question: 'What is "presumptive disability"?', options: ['A disability that is presumed to not exist', 'Certain losses (sight, hearing, speech, loss of limbs) that automatically qualify as total disability regardless of ability to work', 'A temporary disability', 'A disability waiting to be confirmed'], correctIndex: 1, rationale: 'Presumptive disability means certain severe losses (loss of sight in both eyes, loss of both hands or feet, loss of speech or hearing) are automatically considered total disability, often waiving the elimination period.' },
  { id: 233, category: 'Policy Provisions', question: 'In health insurance, what is the "relation of earnings to insurance" provision?', options: ['A provision about agent earnings', 'A provision that limits disability income benefits so they don\'t exceed the insured\'s actual earnings at time of disability', 'A tax provision', 'A provision about premium costs'], correctIndex: 1, rationale: 'This provision prevents over-insurance by limiting the total disability benefits from all sources to the insured\'s actual earnings at the time of disability. Excess coverage premiums are refunded.' },
  { id: 234, category: 'Policy Provisions', question: 'What is the "unpaid premium" provision?', options: ['A penalty for late payment', 'Any premium due but unpaid at the time of the insured\'s death will be deducted from the policy proceeds', 'Premium forgiveness', 'A provision requiring prepayment'], correctIndex: 1, rationale: 'If the insured dies during the grace period with an unpaid premium, the owed premium amount is deducted from the death benefit proceeds before payment to the beneficiary.' },
  { id: 235, category: 'Policy Provisions', question: 'What is "conversion privilege" in group insurance?', options: ['Converting the group to individual policies', 'The right of a departing group member to convert to an individual policy without evidence of insurability', 'Converting health to life insurance', 'A privilege for group administrators'], correctIndex: 1, rationale: 'The conversion privilege allows employees leaving a group plan to convert their group coverage to an individual policy without proving insurability, typically within 31 days of leaving the group.' },
  { id: 236, category: 'Policy Provisions', question: 'What is a "contingent beneficiary"?', options: ['The primary beneficiary', 'The backup beneficiary who receives proceeds if the primary beneficiary predeceases the insured', 'A conditional beneficiary', 'A temporary beneficiary'], correctIndex: 1, rationale: 'A contingent (secondary) beneficiary receives the death benefit only if the primary beneficiary dies before the insured or is otherwise unable to receive the proceeds.' },
  { id: 237, category: 'Policy Provisions', question: 'What is the "physical exam and autopsy" provision in health insurance?', options: ['Requires a physical before purchasing', 'Gives the insurer the right to examine the insured during a claim and to request an autopsy in case of death', 'Requires annual physicals', 'A provision for fitness programs'], correctIndex: 1, rationale: 'This mandatory provision gives the insurer the right to have the insured examined by a physician of its choice while a claim is pending, and to request an autopsy where not prohibited by law.' },
  { id: 238, category: 'Policy Provisions', question: 'What is the "change of occupation" provision in disability insurance?', options: ['Coverage when changing jobs', 'Allows the insurer to adjust benefits or premiums if the insured changes to a more or less hazardous occupation', 'A provision for career counseling', 'Automatic coverage for any job'], correctIndex: 1, rationale: 'If the insured changes to a more hazardous occupation, benefits may be reduced to what the premium would have purchased. If they change to a less hazardous occupation, the insurer refunds the excess premium.' },

  // ═══════════════════════════════════════
  // ANNUITIES — ADVANCED (12 questions)
  // ═══════════════════════════════════════
  { id: 239, category: 'Annuities', question: 'What is a "period certain" annuity payout?', options: ['Payments for life', 'Payments guaranteed for a specific number of years, regardless of whether the annuitant lives or dies', 'Payments during uncertain times', 'Payments for one year only'], correctIndex: 1, rationale: 'A period certain annuity guarantees payments for a set number of years (e.g., 10, 15, 20). If the annuitant dies before the period ends, a beneficiary receives the remaining payments.' },
  { id: 240, category: 'Annuities', question: 'What is a "refund annuity"?', options: ['An annuity that gives your money back', 'An annuity that guarantees the annuitant or beneficiary will receive at least the total amount of premiums paid', 'A refundable annuity purchase', 'An annuity with a money-back guarantee'], correctIndex: 1, rationale: 'A refund annuity guarantees that total payments will at least equal the purchase price. If the annuitant dies before receiving the full amount, the remaining balance is paid to a beneficiary (cash refund or installment refund).' },
  { id: 241, category: 'Annuities', question: 'What is a "subaccount" in a variable annuity?', options: ['A secondary bank account', 'An investment option within a variable annuity, similar to a mutual fund', 'A checking account', 'A sub-savings account'], correctIndex: 1, rationale: 'Subaccounts are the investment options available within a variable annuity. They function like mutual funds, investing in stocks, bonds, or money market instruments. The annuity value fluctuates based on subaccount performance.' },
  { id: 242, category: 'Annuities', question: 'What is "annuitization"?', options: ['Buying an annuity', 'The irrevocable process of converting an annuity\'s accumulated value into a stream of periodic income payments', 'Cancelling an annuity', 'Transferring an annuity'], correctIndex: 1, rationale: 'Annuitization converts the accumulated value into periodic payments. Once annuitized, the decision is typically irrevocable — the owner cannot access the lump sum and receives only the scheduled payments.' },
  { id: 243, category: 'Annuities', question: 'What are "accumulation units" in a variable annuity?', options: ['Shares of stock', 'Accounting measures representing the owner\'s share of the subaccount during the accumulation phase', 'Units of time', 'Premium payment installments'], correctIndex: 1, rationale: 'During the accumulation phase, variable annuity contributions purchase accumulation units. The value of each unit fluctuates based on investment performance. At annuitization, they convert to annuity units.' },
  { id: 244, category: 'Annuities', question: 'What are "annuity units"?', options: ['Same as accumulation units', 'Accounting measures that determine the amount of each payment during the payout phase of a variable annuity', 'Units measuring annuity length', 'Premium payment units'], correctIndex: 1, rationale: 'Annuity units replace accumulation units at annuitization. The number of annuity units stays fixed, but the dollar value of each unit fluctuates with investment performance, causing variable payments.' },
  { id: 245, category: 'Annuities', question: 'What is a "guaranteed minimum withdrawal benefit" (GMWB) rider?', options: ['A free withdrawal provision', 'An optional rider guaranteeing the owner can withdraw a minimum percentage annually regardless of market performance', 'A guaranteed premium refund', 'A withdrawal penalty waiver'], correctIndex: 1, rationale: 'A GMWB rider guarantees the owner can withdraw a specified percentage (typically 4-7%) of the benefit base annually, even if the account value drops to zero due to poor investment performance.' },
  { id: 246, category: 'Annuities', question: 'What is a "mortality and expense" (M&E) charge in a variable annuity?', options: ['A death benefit fee', 'An annual fee charged by the insurer to cover the death benefit guarantee and administrative expenses', 'A medical expense charge', 'A tax on annuity earnings'], correctIndex: 1, rationale: 'The M&E charge is an annual fee (typically 1-1.5% of account value) that covers the insurer\'s risk in providing a guaranteed minimum death benefit and covers administrative expenses.' },
  { id: 247, category: 'Annuities', question: 'Can an annuity be exchanged for a life insurance policy under Section 1035?', options: ['Yes, freely', 'No, an annuity cannot be exchanged for a life insurance policy tax-free', 'Only if the same insurer issues both', 'Only for term insurance'], correctIndex: 1, rationale: 'Under Section 1035, an annuity CANNOT be exchanged for a life insurance policy tax-free. The allowed exchanges are: life to life, life to annuity, annuity to annuity. Not annuity to life.' },
  { id: 248, category: 'Annuities', question: 'What is a "bonus annuity"?', options: ['An annuity with bonus features', 'An annuity that adds a bonus percentage (typically 1-10%) to the initial premium or contributions', 'A free annuity', 'An annuity with extra payments'], correctIndex: 1, rationale: 'A bonus annuity adds a bonus percentage to contributions, effectively boosting the initial account value. However, these often come with longer surrender periods and higher ongoing fees to offset the bonus.' },
  { id: 249, category: 'Annuities', question: 'What is a "longevity annuity" (DIA/QLAC)?', options: ['An annuity for young people', 'A deferred income annuity that begins payments at an advanced age (typically 80-85) to protect against outliving savings', 'A short-term annuity', 'An annuity with longevity bonuses'], correctIndex: 1, rationale: 'A longevity annuity (Deferred Income Annuity) delays payments until an advanced age, providing income protection against outliving one\'s savings. A QLAC is the qualified retirement plan version.' },
  { id: 250, category: 'Annuities', question: 'What is "systematic withdrawal" from an annuity?', options: ['Withdrawing the entire balance', 'Taking regular, scheduled partial withdrawals from an annuity without annuitizing the contract', 'An automatic surrender', 'A forced distribution'], correctIndex: 1, rationale: 'Systematic withdrawals allow the owner to take regular partial distributions without annuitizing. The owner retains control of the remaining balance and can adjust or stop withdrawals, unlike irrevocable annuitization.' },

  // ═══════════════════════════════════════
  // FEDERAL TAX — ADVANCED (13 questions)
  // ═══════════════════════════════════════
  { id: 251, category: 'Federal Tax', question: 'What is "income in respect of a decedent" (IRD) related to life insurance?', options: ['Income earned after death', 'Income that was owed to the deceased but not received before death — it is taxable to the recipient', 'A type of death benefit', 'Insurance premium refunds'], correctIndex: 1, rationale: 'IRD is income the deceased was entitled to but hadn\'t received before death (like unpaid salary, IRA distributions). Unlike life insurance death benefits, IRD is taxable as ordinary income to the recipient.' },
  { id: 252, category: 'Federal Tax', question: 'Are accelerated death benefits taxable?', options: ['Always taxable', 'Generally tax-free if the insured is terminally or chronically ill', 'Taxed as capital gains', 'Only the first $50,000 is tax-free'], correctIndex: 1, rationale: 'Accelerated death benefits paid to a terminally ill insured (expected to die within 24 months) are generally received income tax-free under IRC Section 101(g). Benefits for chronically ill may also qualify.' },
  { id: 253, category: 'Federal Tax', question: 'How are employer-paid health insurance premiums treated for tax purposes?', options: ['Taxable to the employee', 'Tax-deductible for the employer and not taxable income to the employee', 'Not deductible for the employer', 'Taxed at capital gains rates'], correctIndex: 1, rationale: 'Employer-paid health insurance premiums are tax-deductible as a business expense for the employer. They are excluded from the employee\'s taxable income, making this a significant tax benefit.' },
  { id: 254, category: 'Federal Tax', question: 'What is a "Section 125" cafeteria plan?', options: ['A restaurant benefit plan', 'An employer benefit plan allowing employees to choose between taxable cash and qualified tax-free benefits', 'A food service insurance plan', 'A retirement dining benefit'], correctIndex: 1, rationale: 'A Section 125 cafeteria plan allows employees to choose between receiving cash (taxable) or qualified benefits (health insurance, FSA, etc.) on a pre-tax basis, reducing their taxable income.' },
  { id: 255, category: 'Federal Tax', question: 'What is the tax treatment of a "split-dollar" life insurance arrangement?', options: ['Both parties get full tax benefits', 'The employer and employee share the cost of a life insurance policy, with specific tax rules governing who pays tax on the economic benefit', 'Completely tax-free for both parties', 'Fully taxable to the employee'], correctIndex: 1, rationale: 'In a split-dollar arrangement, the employer and employee share the premium costs and benefits. The economic benefit to the employee (cost of pure insurance protection) is taxable income.' },
  { id: 256, category: 'Federal Tax', question: 'What is the "three-year rule" for life insurance and estate taxes?', options: ['A 3-year waiting period for coverage', 'If a policy owner transfers a life insurance policy and dies within 3 years, the death benefit is included in their taxable estate', 'Policies must be held for 3 years', 'A 3-year contestability period'], correctIndex: 1, rationale: 'Under the 3-year rule, if a policyholder transfers ownership of a life insurance policy (to remove it from their estate) and dies within 3 years of the transfer, the death benefit is still included in their taxable estate.' },
  { id: 257, category: 'Federal Tax', question: 'Are proceeds from a "business overhead expense" disability policy taxable?', options: ['No, always tax-free', 'Yes, benefits are taxable, but premiums are tax-deductible as a business expense', 'Only partially taxable', 'Taxed as capital gains'], correctIndex: 1, rationale: 'Business overhead expense (BOE) disability insurance premiums are tax-deductible as a business expense. However, the benefits received are taxable income to the business.' },
  { id: 258, category: 'Federal Tax', question: 'What is a "charitable remainder trust" (CRT) using life insurance?', options: ['A trust for charity only', 'A trust providing income to the donor during their lifetime with the remainder going to charity, often funded by life insurance', 'A life insurance policy for charities', 'A trust that holds insurance premiums'], correctIndex: 1, rationale: 'A CRT provides income to the donor (or beneficiary) for life or a term of years, with the remaining assets going to charity. Life insurance can replace the donated assets for heirs.' },
  { id: 259, category: 'Federal Tax', question: 'What is "FIFO" vs "LIFO" taxation in insurance products?', options: ['Inventory methods only', 'FIFO (first in, first out) applies to non-MEC life insurance withdrawals (basis first); LIFO (last in, first out) applies to MECs and annuities (earnings first)', 'There is no difference', 'Both apply to all insurance'], correctIndex: 1, rationale: 'Non-MEC life insurance uses FIFO — withdrawals come from basis (premiums paid) first, so they\'re tax-free until basis is exhausted. MECs and annuities use LIFO — earnings come out first and are taxable.' },
  { id: 260, category: 'Federal Tax', question: 'Are self-employed individuals allowed to deduct health insurance premiums?', options: ['No, never', 'Yes, self-employed individuals can deduct 100% of health insurance premiums for themselves and their families', 'Only 50% is deductible', 'Only if incorporated'], correctIndex: 1, rationale: 'Self-employed individuals can deduct 100% of health insurance premiums paid for themselves, their spouse, and dependents as an adjustment to income (above-the-line deduction), not as an itemized deduction.' },
  { id: 261, category: 'Federal Tax', question: 'What is the tax treatment of "personally owned" disability insurance?', options: ['Premiums are deductible; benefits are taxable', 'Premiums are NOT deductible; benefits are received tax-free', 'Both premiums and benefits are tax-free', 'Both premiums and benefits are taxable'], correctIndex: 1, rationale: 'When an individual pays disability insurance premiums with after-tax dollars, the premiums are not deductible. However, any benefits received are income tax-free.' },
  { id: 262, category: 'Federal Tax', question: 'What is "generation-skipping transfer tax" (GSTT) related to life insurance?', options: ['A tax on skipping premiums', 'A federal tax on transfers of wealth to beneficiaries two or more generations below the transferor', 'A tax on policy transfers', 'A state inheritance tax'], correctIndex: 1, rationale: 'The GSTT applies to transfers (including life insurance) that skip a generation (e.g., grandparent to grandchild). Life insurance trusts are often used to help mitigate this tax.' },
  { id: 263, category: 'Federal Tax', question: 'What is the "goodover" provision related to group life insurance?', options: ['A tax benefit for good behavior', 'Tax rules requiring employees to report the cost of employer-provided group term life insurance over $50,000 as income', 'A provision for group policy transfers', 'A premium discount'], correctIndex: 1, rationale: 'The "goodover" concept refers to IRC Section 79: employer-provided group term life insurance over $50,000 creates a taxable benefit to the employee based on IRS Table I rates (cost per $1,000 of coverage by age).' },

  // ═══════════════════════════════════════
  // QUALIFIED PLANS — ADVANCED (12 questions)
  // ═══════════════════════════════════════
  { id: 264, category: 'Qualified Plans', question: 'What is a "Roth 401(k)"?', options: ['A separate Roth IRA', 'A 401(k) option allowing employees to make after-tax contributions with tax-free qualified withdrawals', 'A traditional 401(k) with a Roth name', 'A government retirement plan'], correctIndex: 1, rationale: 'A Roth 401(k) combines features of a Roth IRA and traditional 401(k). Contributions are made with after-tax dollars, and qualified withdrawals (after age 59½ and 5-year holding) are completely tax-free.' },
  { id: 265, category: 'Qualified Plans', question: 'What is a "target-date fund" in retirement plans?', options: ['A fund with a target return', 'A mutual fund that automatically adjusts its asset allocation to become more conservative as the target retirement date approaches', 'A fund that targets specific stocks', 'A fixed-income fund'], correctIndex: 1, rationale: 'Target-date funds automatically shift from aggressive investments (stocks) to conservative investments (bonds) as the target retirement date approaches, providing a hands-off investment approach.' },
  { id: 266, category: 'Qualified Plans', question: 'What is a "direct rollover" vs "indirect rollover"?', options: ['They are the same', 'Direct: funds transfer institution-to-institution; Indirect: funds are paid to the individual who must redeposit within 60 days', 'Direct is faster; indirect is slower', 'Direct requires taxes; indirect does not'], correctIndex: 1, rationale: 'A direct rollover transfers funds directly between institutions with no withholding. An indirect rollover pays the individual (with 20% mandatory withholding); the full amount must be redeposited within 60 days.' },
  { id: 267, category: 'Qualified Plans', question: 'What is a "prohibited transaction" in retirement plans?', options: ['Any withdrawal before 59½', 'Transactions between a plan and disqualified persons that are specifically forbidden by ERISA', 'Contributing too much', 'Investing in stocks'], correctIndex: 1, rationale: 'Prohibited transactions include loans or sales between the plan and disqualified persons (fiduciaries, plan sponsors, family members), self-dealing, and improper use of plan assets. Violations carry severe penalties.' },
  { id: 268, category: 'Qualified Plans', question: 'What is "cliff vesting"?', options: ['Vesting that occurs gradually', 'An employee becomes 100% vested in employer contributions after a specific period (typically 3 years), with 0% vesting before that', 'Immediate vesting', 'Vesting based on performance'], correctIndex: 1, rationale: 'Cliff vesting means the employee has 0% ownership of employer contributions until a specified date (often 3 years), at which point they become 100% vested. There is no partial vesting before the cliff.' },
  { id: 269, category: 'Qualified Plans', question: 'What is "graded vesting"?', options: ['Same as cliff vesting', 'Vesting that increases gradually over time (e.g., 20% per year over 5 years) until 100% is reached', 'Vesting based on grades', 'Instant vesting'], correctIndex: 1, rationale: 'Graded vesting provides gradually increasing ownership of employer contributions over time. A common schedule is 20% per year over 5 years, or 2-6 year graded vesting under ERISA.' },
  { id: 270, category: 'Qualified Plans', question: 'What is an "Employee Stock Ownership Plan" (ESOP)?', options: ['A stock trading account', 'A qualified defined contribution plan that invests primarily in the employer\'s stock, giving employees ownership interest', 'A stock option for executives only', 'A mutual fund plan'], correctIndex: 1, rationale: 'An ESOP is a qualified retirement plan that invests primarily in the sponsoring company\'s stock. It provides employees with ownership interest and can be used as a succession planning tool for business owners.' },
  { id: 271, category: 'Qualified Plans', question: 'What is the "top-heavy" rule for qualified plans?', options: ['Plans with too many participants', 'If more than 60% of plan assets benefit key employees, the plan must provide minimum contributions or benefits for non-key employees', 'Plans with the highest returns', 'Plans for top executives only'], correctIndex: 1, rationale: 'A plan is top-heavy when more than 60% of accumulated benefits or account balances belong to key employees. Top-heavy plans must provide minimum contributions (3% of compensation) for non-key employees.' },
  { id: 272, category: 'Qualified Plans', question: 'What is a "money purchase pension plan"?', options: ['A plan where you buy a pension', 'A defined contribution plan requiring the employer to contribute a fixed percentage of each employee\'s compensation annually', 'A pension plan funded by employees only', 'A plan for purchasing annuities'], correctIndex: 1, rationale: 'A money purchase pension plan is a defined contribution plan with mandatory employer contributions at a fixed percentage. Unlike profit-sharing, contributions are required regardless of profits.' },
  { id: 273, category: 'Qualified Plans', question: 'What is the "substantially equal periodic payments" (SEPP) exception?', options: ['Equal premium payments', 'An exception to the 10% early withdrawal penalty allowing regular distributions from IRAs before age 59½', 'A payment plan for premiums', 'Equal beneficiary distributions'], correctIndex: 1, rationale: 'The SEPP exception (Rule 72(t)) allows IRA owners to take penalty-free distributions before age 59½ if they take substantially equal periodic payments based on life expectancy for at least 5 years or until age 59½.' },
  { id: 274, category: 'Qualified Plans', question: 'What is a "solo 401(k)"?', options: ['A 401(k) with one investment option', 'A 401(k) plan designed for self-employed individuals with no employees other than a spouse', 'A 401(k) for singles only', 'A simplified 401(k)'], correctIndex: 1, rationale: 'A solo 401(k) is designed for self-employed individuals with no full-time employees (a spouse can participate). It allows both employee and employer contributions, often resulting in higher total contribution limits.' },
  { id: 275, category: 'Qualified Plans', question: 'What is a "required beginning date" (RBD) for retirement plan distributions?', options: ['The first day of retirement', 'April 1 of the year following the year the account owner turns 73 — the deadline to begin taking RMDs', 'January 1 of the year you retire', 'The date the plan was opened'], correctIndex: 1, rationale: 'The RBD is April 1 of the year following the year the account owner reaches RMD age (currently 73 under SECURE 2.0). RMDs must begin by this date to avoid a 25% excise tax on the amount not withdrawn.' },

  // ═══════════════════════════════════════
  // STATE REGULATIONS — ADVANCED (13 questions)
  // ═══════════════════════════════════════
  { id: 276, category: 'State Regulations', question: 'What is "reciprocity" in insurance licensing?', options: ['Sharing commissions between agents', 'Agreements between states allowing a producer licensed in one state to obtain a license in another state with reduced requirements', 'Mutual insurance arrangements', 'Sharing policyholder data'], correctIndex: 1, rationale: 'Reciprocity agreements between states allow insurance producers to obtain non-resident licenses in other states more easily, often without additional examinations, if their home state has a reciprocal agreement.' },
  { id: 277, category: 'State Regulations', question: 'What is a "non-resident" insurance license?', options: ['A license for non-citizens', 'A license allowing a producer licensed in their home state to sell insurance in another state where they do not reside', 'A temporary license', 'A license for online-only sales'], correctIndex: 1, rationale: 'A non-resident license allows an insurance producer to conduct business in a state other than their home (resident) state. Most states require a valid resident license before granting a non-resident license.' },
  { id: 278, category: 'State Regulations', question: 'What is "file and use" rate regulation?', options: ['Filing taxes on insurance rates', 'Insurers can file rates with the state and begin using them immediately without waiting for prior approval', 'Filing claims to use insurance', 'Filing for a license'], correctIndex: 1, rationale: 'Under file and use, insurers submit rates to the state and can implement them immediately. The state reviews afterward and can disapprove rates later. This contrasts with prior approval, which requires approval before use.' },
  { id: 279, category: 'State Regulations', question: 'What is "use and file" rate regulation?', options: ['Same as file and use', 'Insurers can implement new rates immediately and file them with the state within a specified period after use', 'Using a file to process claims', 'Filing claims and using benefits'], correctIndex: 1, rationale: 'Use and file allows insurers to implement rates immediately and file them with the state within a set timeframe (e.g., 30 days). The state can later disapprove the rates.' },
  { id: 280, category: 'State Regulations', question: 'What is an "alien" insurance company?', options: ['An insurance company from another planet', 'An insurer organized under the laws of a foreign country', 'An out-of-state insurer', 'A newly formed insurer'], correctIndex: 1, rationale: 'An alien insurer is one organized under the laws of another country (e.g., Lloyd\'s of London). A domestic insurer is organized in the state. A foreign insurer is organized in a different US state.' },
  { id: 281, category: 'State Regulations', question: 'What is the difference between "domestic," "foreign," and "alien" insurers?', options: ['No difference', 'Domestic = organized in this state; Foreign = organized in another US state; Alien = organized in another country', 'All are the same legal entity', 'These terms refer to agent types'], correctIndex: 1, rationale: 'Domestic insurers are incorporated in the state where they do business. Foreign insurers are incorporated in a different US state. Alien insurers are incorporated in a foreign country.' },
  { id: 282, category: 'State Regulations', question: 'What is "countersigning"?', options: ['A cosigner on a policy', 'A requirement in some states that a non-resident agent\'s policies be countersigned by a licensed resident agent', 'Signing a policy twice', 'Counter-offers on premiums'], correctIndex: 1, rationale: 'Some states require policies sold by non-resident agents to be countersigned by a licensed resident agent. The resident agent may receive a portion of the commission for this service.' },
  { id: 283, category: 'State Regulations', question: 'What is "fronting" in insurance?', options: ['Being the front person for sales', 'A practice where a licensed insurer issues a policy on behalf of an unlicensed insurer, which bears the actual risk through reinsurance', 'Leading a sales team', 'The front page of a policy'], correctIndex: 1, rationale: 'Fronting occurs when an admitted insurer issues a policy and immediately reinsures the entire risk with a non-admitted insurer. This allows the non-admitted insurer to effectively write business in the state.' },
  { id: 284, category: 'State Regulations', question: 'What is "commingling" of funds?', options: ['Mixing different investment types', 'The illegal practice of mixing client premium funds with the agent\'s personal funds', 'Combining policies', 'Pooling insurance risks'], correctIndex: 1, rationale: 'Commingling is the illegal mixing of premium funds collected from clients with an agent\'s personal funds. Premiums must be kept in a separate trust or fiduciary account until remitted to the insurer.' },
  { id: 285, category: 'State Regulations', question: 'What is an "insurance exchange"?', options: ['Trading insurance policies', 'A marketplace (like the ACA marketplace) where individuals and small businesses can shop for and compare health insurance plans', 'Exchanging one policy for another', 'A stock exchange for insurers'], correctIndex: 1, rationale: 'An insurance exchange (marketplace) is a platform, established under the ACA, where individuals and small businesses can compare and purchase qualified health insurance plans, often with premium subsidies.' },
  { id: 286, category: 'State Regulations', question: 'What is "dual licensing"?', options: ['Having two copies of a license', 'Holding both insurance and securities licenses, required for selling variable products', 'Being licensed in two states', 'Having a life and health license'], correctIndex: 1, rationale: 'Dual licensing means holding both an insurance license and a securities license (Series 6 or 7). This is required to sell variable life insurance and variable annuities, which are considered securities.' },
  { id: 287, category: 'State Regulations', question: 'What is the "Unfair Claims Settlement Practices Act"?', options: ['A law about unfair premiums', 'Model legislation adopted by states that defines unfair claims practices and provides penalties for insurers who engage in them', 'A federal claims law', 'A law about claim deadlines'], correctIndex: 1, rationale: 'This model act, adopted by most states, defines specific unfair claims practices (e.g., failing to acknowledge claims promptly, not attempting fair settlements, compelling policyholders to sue to recover amounts due).' },
  { id: 288, category: 'State Regulations', question: 'What is "state guaranty fund" coverage typically limited to?', options: ['Unlimited coverage', 'A maximum dollar amount per policy (commonly $300,000 for life insurance death benefits and $100,000-$250,000 for cash values)', 'Coverage for one year only', '$50,000 per policy'], correctIndex: 1, rationale: 'State guaranty fund coverage limits vary by state but commonly provide up to $300,000 for life insurance death benefits, $100,000-$250,000 for cash surrender values, and $100,000-$300,000 for health insurance benefits.' },

  // ═══════════════════════════════════════
  // ETHICS & LAW — ADVANCED (12 questions)
  // ═══════════════════════════════════════
  { id: 289, category: 'Ethics & Law', question: 'What is "vicarious liability" in insurance?', options: ['Liability for vices', 'The legal principle that an employer (principal) is liable for the acts of an agent performed within the scope of employment', 'Liability for variable products', 'Personal liability only'], correctIndex: 1, rationale: 'Under vicarious liability (respondeat superior), an insurance company can be held liable for the wrongful acts of its agents committed within the scope of their agency authority.' },
  { id: 290, category: 'Ethics & Law', question: 'What is the "duty to disclose" in insurance?', options: ['Disclosing agent commissions', 'The applicant\'s obligation to reveal all material facts that could affect the insurer\'s decision to issue a policy', 'The insurer\'s duty to disclose profits', 'Disclosing policy dividends'], correctIndex: 1, rationale: 'The duty to disclose requires the insurance applicant to voluntarily reveal all material facts — information that would influence the insurer\'s underwriting decision, even if not specifically asked.' },
  { id: 291, category: 'Ethics & Law', question: 'What is "rescission" of an insurance contract?', options: ['Renewing a contract', 'Voiding a contract from its inception as if it never existed, typically due to material misrepresentation or fraud', 'Modifying a contract', 'Cancelling a contract going forward'], correctIndex: 1, rationale: 'Rescission voids the insurance contract from inception, returning both parties to their pre-contract positions. The insurer refunds premiums but owes no benefits. This requires proof of material misrepresentation or fraud.' },
  { id: 292, category: 'Ethics & Law', question: 'What is "reformation" of an insurance contract?', options: ['Changing the insurer', 'A court-ordered correction of a contract to reflect the true intent of the parties when a mutual mistake has occurred', 'Reforming insurance regulations', 'Adding new terms to a policy'], correctIndex: 1, rationale: 'Reformation is a court remedy that corrects a written contract to accurately reflect the original agreement of the parties when a mutual mistake caused the written document to differ from their intent.' },
  { id: 293, category: 'Ethics & Law', question: 'What is the "parole evidence rule" in insurance?', options: ['Evidence from parolees', 'Oral statements made before or during the formation of a written contract generally cannot be used to change or contradict the written terms', 'Evidence rules for agents', 'A rule about policy wording'], correctIndex: 1, rationale: 'The parol evidence rule prevents the use of prior or contemporaneous oral agreements to modify, contradict, or supplement the terms of a fully integrated written insurance contract.' },
  { id: 294, category: 'Ethics & Law', question: 'What is "comparative negligence" in insurance claims?', options: ['Comparing insurance policies', 'A legal principle that allocates fault between parties based on their respective degrees of negligence', 'Negligent comparison shopping', 'Comparing agent performance'], correctIndex: 1, rationale: 'Comparative negligence assigns fault proportionally among all parties involved. In insurance claims, it determines how much each party contributed to the loss, which affects the claim payout.' },
  { id: 295, category: 'Ethics & Law', question: 'What is an "errors and omissions" (E&O) claim against an agent?', options: ['An administrative filing error', 'A claim alleging the agent made a professional mistake or failed to perform a duty that resulted in financial harm to the client', 'A claim for policy errors', 'An error in commission payments'], correctIndex: 1, rationale: 'An E&O claim alleges the agent was negligent in their professional duties — such as failing to procure requested coverage, recommending unsuitable products, or providing incorrect advice — resulting in client harm.' },
  { id: 296, category: 'Ethics & Law', question: 'What is the "reasonable person" standard in insurance?', options: ['A person of reasonable health', 'A legal standard that measures conduct against what a hypothetical reasonable person would do in similar circumstances', 'A standard for policy pricing', 'A standard for claim processing'], correctIndex: 1, rationale: 'The reasonable person standard is used to evaluate whether an agent\'s actions were appropriate by comparing them to what a reasonable, prudent insurance professional would have done in the same situation.' },
  { id: 297, category: 'Ethics & Law', question: 'What is "anti-money laundering" (AML) compliance in insurance?', options: ['Cleaning dirty money', 'Requirements for insurance companies and agents to detect, prevent, and report suspicious transactions that may involve money laundering', 'A type of insurance coverage', 'Monitoring agent bank accounts'], correctIndex: 1, rationale: 'AML compliance requires insurers and agents to implement programs to detect and report suspicious activities, including filing Suspicious Activity Reports (SARs) and Currency Transaction Reports (CTRs).' },
  { id: 298, category: 'Ethics & Law', question: 'What is a "suitability" obligation for annuity sales?', options: ['Selling any annuity the client requests', 'The requirement that agents ensure an annuity recommendation is suitable based on the client\'s financial situation, needs, and objectives', 'Selling the most expensive annuity', 'A suggestion, not a requirement'], correctIndex: 1, rationale: 'Suitability requires agents to have reasonable grounds for believing an annuity recommendation is appropriate for the client based on their age, income, financial objectives, risk tolerance, and existing coverage.' },
  { id: 299, category: 'Ethics & Law', question: 'What is the "best interest" standard for annuity recommendations?', options: ['Same as suitability', 'A higher standard requiring agents to act in the consumer\'s best interest, without placing the agent\'s financial interest ahead of the consumer\'s', 'Best interest of the insurance company', 'A voluntary guideline'], correctIndex: 1, rationale: 'The best interest standard (adopted via NAIC model regulation) goes beyond suitability, requiring agents to prioritize the consumer\'s interest above their own financial compensation when recommending annuities.' },
  { id: 300, category: 'Ethics & Law', question: 'What is the penalty for an agent conducting insurance business without a valid license?', options: ['A warning letter', 'Fines, imprisonment, or both, depending on state law', 'Suspension of future licensing', 'No penalty in most states'], correctIndex: 1, rationale: 'Conducting insurance business without a valid license is a criminal offense in all states. Penalties typically include substantial fines, possible imprisonment, and being barred from future licensing.' },
];

export default Q;
